41	struct NoMask {
42	  template<class BlkCoord, class TileShape, class ProblemSize>
43	  CUTLASS_DEVICE
44	  int get_trip_count(
45	      BlkCoord const& blk_coord,
46	      TileShape const& tile_shape,
47	      ProblemSize const& problem_size) {
48	
49	    return ceil_div(get<1>(problem_size), get<1>(tile_shape));
50	  }
51	
52	  template<class BlkCoord, class TileShape, class ProblemSize>
53	  CUTLASS_DEVICE
54	  int get_masked_trip_count(
55	      BlkCoord const& blk_coord,
56	      TileShape const& tile_shape,
57	      ProblemSize const& problem_size) {
58	
59	    return 0;
60	  }
61	
62	  template<class BlkCoord, class TileShape, class ProblemSize>
63	  CUTLASS_DEVICE
64	  int get_unmasked_trip_count(
65	      BlkCoord const& blk_coord,
66	      TileShape const& tile_shape,
67	      ProblemSize const& problem_size) {
68	
69	    return get_trip_count(blk_coord, tile_shape, problem_size);
70	  }
71	
72	  template<class AccQK, class IndexQK, class ProblemSize>
73	  CUTLASS_DEVICE
74	  void apply_mask(
75	      AccQK& acc_qk,
76	      IndexQK const& index_qk,
77	      ProblemSize const& problem_size) {
78	
79	    return;
80	  }
81	};
82	
83	struct ResidualMask : NoMask {
84	
85	  using Base = NoMask;
86	
87	  template <class BlkCoord, class TileShape, class ProblemSize>
88	  CUTLASS_DEVICE int get_masked_trip_count(
89	      BlkCoord const& blk_coord,
90	      TileShape const& tile_shape,
91	      ProblemSize const& problem_size) {
92	
93	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
94	      return 1;
95	    }
96	    return 0;
97	  }
98	
99	  template<class BlkCoord, class TileShape, class ProblemSize>
100	  CUTLASS_DEVICE
101	  int get_unmasked_trip_count(
102	      BlkCoord const& blk_coord,
103	      TileShape const& tile_shape,
104	      ProblemSize const& problem_size) {
105	
106	    // if the sequence length does not divide the tile size evenly
107	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
108	      return get_trip_count(blk_coord, tile_shape, problem_size) - 1;
109	    }
110	    return get_trip_count(blk_coord, tile_shape, problem_size);
111	  }
112	
113	  template<class AccQK, class IndexQK, class ProblemSize>
114	  CUTLASS_DEVICE
115	  void apply_mask(
116	      AccQK& acc_qk,
117	      IndexQK const& index_qk,
118	      ProblemSize const& problem_size) {
119	
120	    // This is useful is seqlen_k % kBlockN != 0 since it masks
121	    // the remaining elements out from softmax.
122	    // d % kHeadDim != 0 or seqlen_q % kBlockM do not suffer from similar
123	    // issues as they are transparently taken care of by TMA and the
124	    // epilogue, if it is instantiated with predication support.
125	    CUTLASS_PRAGMA_UNROLL
126	    for (int i = 0; i < size(acc_qk); i++) {
127	      auto pos = index_qk(i);
128	      if (get<1>(pos) >= get<1>(problem_size)) {
129	        acc_qk(i) = -INFINITY;
130	      }
131	    }
132	  }
133	};
