135	struct ResidualMaskForBackward : NoMask {
136	
137	  using Base = NoMask;
138	
139	  template <class BlkCoord, class TileShape, class ProblemSize>
140	  CUTLASS_DEVICE int get_masked_trip_count(
141	      BlkCoord const& blk_coord,
142	      TileShape const& tile_shape,
143	      ProblemSize const& problem_size) {
144	
145	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
146	      return 1;
147	    }
148	    return 0;
149	  }
150	
151	  template<class BlkCoord, class TileShape, class ProblemSize>
152	  CUTLASS_DEVICE
153	  int get_unmasked_trip_count(
154	      BlkCoord const& blk_coord,
155	      TileShape const& tile_shape,
156	      ProblemSize const& problem_size) {
157	
158	    // if the sequence length does not divide the tile size evenly
159	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
160	      return get_trip_count(blk_coord, tile_shape, problem_size) - 1;
161	    }
162	    return get_trip_count(blk_coord, tile_shape, problem_size);
163	  }
164	
165	  template<class AccQK, class IndexQK, class ProblemSize>
166	  CUTLASS_DEVICE
167	  void apply_mask(
168	      AccQK& acc_qk,
169	      IndexQK const& index_qk,
170	      ProblemSize const& problem_size) {
171	
172	    // This is useful is seqlen_k % kBlockN != 0 since it masks
173	    // the remaining elements out from softmax.
174	    // d % kHeadDim != 0 or seqlen_q % kBlockM do not suffer from similar
175	    // issues as they are transparently taken care of by TMA and the
176	    // epilogue, if it is instantiated with predication support.
177	    CUTLASS_PRAGMA_UNROLL
178	    for (int i = 0; i < size(acc_qk); i++) {
179	      auto pos = index_qk(i);
180	      if (! elem_less(pos, select<0,1>(problem_size))) {
181	        acc_qk(i) = -INFINITY;
182	      }
183	    }
184	  }
185	};
186	
187	// There are two ways to do causal if N_Q != N_K
188	// (1) The Q is at the beginning of the matrix
189	// (2) The Q is at the end of the matrix
190	template<bool kIsQBegin = true>
191	struct CausalMask : NoMask {
192	
193	  using Base = NoMask;
194	
195	  static constexpr bool IsQBegin = kIsQBegin;
196	
197	  template<class BlkCoord, class TileShape, class ProblemSize>
198	  CUTLASS_DEVICE
199	  int get_trip_count(
200	      BlkCoord const& blk_coord,
201	      TileShape const& tile_shape,
202	      ProblemSize const& problem_size) {
203	
204	    // See note below on different ways to think about causal attention
205	    // Again, we'd add the offset_q into the max_blocks_q calculation
206	    int max_blocks_k = Base::get_trip_count(blk_coord, tile_shape, problem_size);
207	    if constexpr (IsQBegin) {
208	      int max_blocks_q = ceil_div((get<0>(blk_coord) + 1) * get<0>(tile_shape), get<1>(tile_shape));
209	      return std::min(max_blocks_k, max_blocks_q);
210	    } else {
211	      const int offset_q = get<1>(problem_size) - get<0>(problem_size);
212	      int max_blocks_q = ceil_div((get<0>(blk_coord) + 1) * get<0>(tile_shape) + offset_q, get<1>(tile_shape));
213	      return std::min(max_blocks_k, max_blocks_q);
214	    }
215	  }
216	
217	  template<class BlkCoord, class TileShape, class ProblemSize>
218	  CUTLASS_DEVICE
219	  int get_masked_trip_count(
220	      BlkCoord const& blk_coord,
221	      TileShape const& tile_shape,
222	      ProblemSize const& problem_size) {
223	
224	    int trip_count = get_trip_count(blk_coord, tile_shape, problem_size);
225	    if constexpr (IsQBegin) {
226	      return std::min(trip_count, int(ceil_div(size<0>(tile_shape), size<1>(tile_shape))));
227	    } else {
228	      const int corner_count = int((get<1>(problem_size) % get<1>(tile_shape) || get<0>(problem_size) % get<0>(tile_shape))) ;
229	      return std::min(trip_count, int(ceil_div(get<0>(tile_shape), get<1>(tile_shape))) + corner_count);
230	    }
231	  }
232	
233	  template<class BlkCoord, class TileShape, class ProblemSize>
234	  CUTLASS_DEVICE
235	  int get_unmasked_trip_count(
236	      BlkCoord const& blk_coord,
237	      TileShape const& tile_shape,
238	      ProblemSize const& problem_size) {
239	
240	    return get_trip_count(blk_coord, tile_shape, problem_size) - get_masked_trip_count(blk_coord, tile_shape, problem_size);
241	  }
242	
243	  template<class AccQK, class IndexQK, class ProblemSize>
244	  CUTLASS_DEVICE
245	  void apply_mask(
246	      AccQK& acc_qk,
247	      IndexQK const& index_qk,
248	      ProblemSize const& problem_size) {
249	
250	    // There are two ways to do causal if N_Q != N_K
251	    // (1) is to assume that the Q is at the beginning of the matrix
252	    //    - this is the default setting.
253	    // (2) is that it is at the end of the matrix
254	    //    - this is usually what we want for inference settings
255	    //      where we only compute the next row and use cache for the rest
256	    //    - if you'd like this, you only need to set kIsQBegin=false
257	
258	    if constexpr (IsQBegin) {
259	      CUTLASS_PRAGMA_UNROLL
260	      for (int i = 0; i < size(acc_qk); i++) {
261	        auto pos = index_qk(i);
262	        if ((get<0>(pos) < get<1>(pos)) || (get<1>(pos) >= get<1>(problem_size))) {
263	          acc_qk(i) = -INFINITY;
264	        }
265	      }
266	    } else {
267	      const auto offset_q = get<1>(problem_size) - get<0>(problem_size);
268	      CUTLASS_PRAGMA_UNROLL
269	      for (int i = 0; i < size(acc_qk); i++) {
270	        auto pos = index_qk(i);
271	        if ((get<0>(pos) + offset_q < get<1>(pos)) || (get<1>(pos) >= get<1>(problem_size))) {
272	          acc_qk(i) = -INFINITY;
273	        }
274	      }
275	    }
276	  }
277	};
278	
279	template<bool kIsQBegin = true>
280	struct CausalForBackwardMask : CausalMask<kIsQBegin>, ResidualMaskForBackward {
281	
282	  using Base = CausalMask<kIsQBegin>;
283	
284	  template<class AccQK, class IndexQK, class ProblemSize>
285	  CUTLASS_DEVICE
286	  void apply_mask(
287	      AccQK& acc_qk,
288	      IndexQK const& index_qk,
289	      ProblemSize const& problem_size) {
290	
291	    // There are two ways to do causal if N_Q != N_K
292	    // (1) is to assume that the Q is at the beginning of the matrix
293	    //    - this is what we demonstrate here
294	    // (2) is that it is at the end of the matrix
295	    //    - this is usually what we want for inference settings
296	    //      where we only compute the next row and use cache for the rest
297	    //    - if you'd like this, you only need to add an offset like so:
298	    //      get<0>(pos) + offset_q < get<1>(pos)
299	    int offset_q = 0;
300	    if constexpr (!kIsQBegin) {
301	      offset_q = get<1>(problem_size) - get<0>(problem_size);
302	    }
303	
304	    CUTLASS_PRAGMA_UNROLL
305	    for (int i = 0; i < size(acc_qk); i++) {
306	      auto pos = index_qk(i);
307	      bool masked = (get<0>(pos) + offset_q < get<1>(pos)) || !elem_less(pos, problem_size);
308	      if (masked) {
309	        acc_qk(i) = -INFINITY;
310	      }
311	    }
312	  }
313	
314	};
315	
316	struct VariableLength {
317	  int max_length;
318	  int* cumulative_length = nullptr;
319	  int total_length = -1;
320	
321	  CUTE_HOST_DEVICE operator int() const {
322	    return max_length;
323	  }
324	};
325	
326	template<class T> struct is_variable_length_impl : std::false_type {};
327	template<> struct is_variable_length_impl<VariableLength> : std::true_type {};
328	template<class T> constexpr bool is_variable_length_v = is_variable_length_impl<remove_cvref_t<T>>::value;
329	
330	template<class Shape, class Idx>
331	CUTE_HOST_DEVICE
332	constexpr auto
333	apply_variable_length(Shape const& shape, Idx const& idx) {
334	  return transform_leaf(shape, [&](auto const& s) {
335	    if constexpr (is_variable_length_v<decltype(s)>) {
336	      return s.cumulative_length[idx+1] - s.cumulative_length[idx];
337	    }
338	    else {
339	      return s;
340	    }
341	  });
342	}
343	
344	template<class Shape, class Coord, class Idx>
345	CUTE_HOST_DEVICE
346	constexpr auto
347	apply_variable_length(Shape const& shape, Coord const& coord, Idx const& idx) {
348	  auto new_shape = apply_variable_length(shape, idx);
349	  auto new_coord = transform_leaf(shape, coord, [&](auto const& s, auto const& c) {
350	    if constexpr (is_variable_length_v<decltype(s)>) {
351	      return cute::make_tuple(c, s.cumulative_length[idx]);
352	    }
353	    else {
354	      return c;
355	    }
356	  });
357	  return cute::make_tuple(new_shape, new_coord);
358	}
359	
360	template<class Shape, class Coord>
361	CUTE_HOST_DEVICE
362	constexpr auto
363	apply_variable_length_offset(Shape const& shape, Coord const& coord) {
364	  auto idx = back(back(coord));
365	  auto result_shape = transform_leaf(shape, [&](auto const& s) {
366	    if constexpr (is_variable_length_v<decltype(s)>) {
367	      return s.cumulative_length[idx+1] - s.cumulative_length[idx];
368	    }
369	    else {
370	      return s;
371	    }
372	  });
373	  auto result_offset = transform_leaf(coord, shape, [&](auto const& c, auto const& s) {
374	    if constexpr (is_variable_length_v<decltype(s)>) {
375	      return s.cumulative_length[idx];
376	    }
377	    else {
378	      return _0{};
379	    }
380	  });
381	  return cute::make_tuple(result_shape, result_offset);
382	}
383	
384	}  // namespace cutlass::fmha::collective
385	
386	namespace cute {
387	
388	template<>
389	struct is_integral<cutlass::fmha::collective::VariableLength> : true_type {};
390	
391	CUTE_HOST_DEVICE
392	void print(cutlass::fmha::collective::VariableLength a) {
393	  printf("Varlen<%d, %p>", a.max_length, a.cumulative_length);
394	}
395	
396	}
