43	
44	using namespace cute;
45	
46	template<
47	  class Element,
48	  class StrideQ,
49	  class StrideK,
50	  class StrideV,
51	  class CollectiveMmaQK,
52	  class CollectiveMmaPV,
53	  class SmemLayoutQ,
54	  class SmemLayoutK,
55	  class SmemLayoutV,
56	  class TensorStorage,
57	  class PipelineQ,
58	  class PipelineKV,
59	  class Mask,
60	  class TileShape,
61	  class OrderLoadEpilogue = cute::false_type
62	>
63	struct Sm100MlaFwdLoadTmaWarpspecialized {
64	
65	  using TileShapeQK = typename CollectiveMmaQK::TileShape;
66	  using TileShapePV = typename CollectiveMmaPV::TileShape;
67	
68	  static constexpr int TransactionBytesLoadK = cutlass::bits_to_bytes(cosize(take<0,3>(SmemLayoutK{})) * cute::sizeof_bits_v<Element>);
69	  static constexpr int TransactionBytesLoadV = cutlass::bits_to_bytes(cosize(take<0,3>(SmemLayoutV{})) * cute::sizeof_bits_v<Element>);
70	
71	  static const int NumWarpsEpilogue = 1;
72	  static const int NumWarpsLoad = 1;
73	
74	  struct Arguments {
75	    const Element* ptr_Q;
76	    StrideQ dQ;
77	    const Element* ptr_K;
78	    StrideK dK;
79	    const Element* ptr_V;
80	    StrideV dV;
81	  };
82	
83	  using TMA_Q = typename CollectiveMmaQK::Params::TMA_A;
84	  using TMA_K = typename CollectiveMmaQK::Params::TMA_B;
85	  using TMA_V = typename CollectiveMmaPV::Params::TMA_B;
86	
87	  struct Params {
88	    TMA_Q tma_load_q;
89	    TMA_K tma_load_k;
90	    TMA_V tma_load_v;
91	  };
92	
93	  template<class ProblemShape>
94	  static Params to_underlying_arguments(
95	      ProblemShape const& problem_shape,
96	      Arguments const& args,
97	      void* workspace) {
98	
99	    auto ptr_Q = args.ptr_Q;
100	    auto ptr_K = args.ptr_K;
101	    auto ptr_V = args.ptr_V;
102	    auto dQ = args.dQ;
103	    auto dK = args.dK;
104	    auto dV = args.dV;
105	
106	    using IntProblemShape = cute::tuple<int, int, int, cute::tuple<cute::tuple<int, int>, int>>;
107	
108	    IntProblemShape problem_shape_qk;
109	    if constexpr (is_variable_length_v<tuple_element_t<0, ProblemShape>>) {
110	      auto cumulative_length_q = get<0>(problem_shape).cumulative_length;
111	      auto cumulative_length_k = get<1>(problem_shape).cumulative_length;
112	      if (cumulative_length_q != nullptr && cumulative_length_k != nullptr ) {
113	          get<0>(problem_shape_qk) = get<0>(problem_shape).total_length;
114	          get<1>(problem_shape_qk) = get<1>(problem_shape).total_length;
115	          get<2>(problem_shape_qk) = get<2, 0>(problem_shape) + get<2, 1>(problem_shape);
116	          get<3>(problem_shape_qk) = get<3>(problem_shape);
117	      }
118	    } else {
119	      problem_shape_qk = replace<2>(problem_shape, get<2, 0>(problem_shape) + get<2, 1>(problem_shape));;
120	    }
121	
122	    get<0>(problem_shape_qk) = max(1, get<0>(problem_shape_qk));
123	    get<1>(problem_shape_qk) = max(1, get<1>(problem_shape_qk));
124	
125	    auto problem_shape_pv = replace<1>(select<0,2,1,3>(problem_shape_qk), get<2, 0>(problem_shape));
126	
127	    auto params_qk = CollectiveMmaQK::to_underlying_arguments(
128	        problem_shape_qk,
129	        typename CollectiveMmaQK::Arguments {
130	            ptr_Q, dQ,
131	            ptr_K, dK,
132	        }, /*workspace=*/ nullptr);
133	
134	    auto params_pv = CollectiveMmaPV::to_underlying_arguments(
135	        problem_shape_pv,
136	        typename CollectiveMmaPV::Arguments {
137	            ptr_K, dK,  // never used, dummy
138	            ptr_V, select<1,0,2>(dV),
139	        }, /*workspace=*/ nullptr);
140	
141	    return Params{
142	        params_qk.tma_load_a,
143	        params_qk.tma_load_b,
144	        params_pv.tma_load_b
145	    };
146	  }
147	
148	
149	  CUTLASS_DEVICE
150	  static void prefetch_tma_descriptors(Params const& params) {
151	    cute::prefetch_tma_descriptor(params.tma_load_q.get_tma_descriptor());
152	    cute::prefetch_tma_descriptor(params.tma_load_k.get_tma_descriptor());
153	    cute::prefetch_tma_descriptor(params.tma_load_v.get_tma_descriptor());
154	  }
155	
156	  template<class BlkCoord, class ProblemShape, class ParamsProblemShape>
157	  CUTLASS_DEVICE void
158	  load(
159	      BlkCoord const& blk_coord_in, ProblemShape const& problem_shape,
160	      Params const& params, ParamsProblemShape const& params_problem_shape,
161	      TensorStorage& storage,
162	      PipelineQ& pipeline_q, typename PipelineQ::PipelineState& pipeline_q_producer_state,
163	      PipelineKV& pipeline_kv, typename PipelineKV::PipelineState& pipeline_kv_producer_state) {
164	
165	    BlkCoord blk_coord_q = blk_coord_in;
166	    BlkCoord blk_coord_kv = blk_coord_in;
167	
168	    auto problem_shape_qk = replace<2>(problem_shape, get<2, 0>(problem_shape) + get<2, 1>(problem_shape));
169	    auto problem_shape_v = replace<2>(problem_shape, get<2, 0>(problem_shape));
170	
171	    int mask_tile_count = Mask{}.get_trip_count(blk_coord_in, TileShape{}, problem_shape);
172	
173	    using X = Underscore;
174	
175	    // this one is only executed by one thread, no need to elect_one
176	
177	    // Q1, K1, Q2, V1, K2, V2, K3, V3, ...
178	    // two pipes: Q and KV
179	    // from Memory (prod) to TensorCore (cons)
180	
181	    // compute gQ, sQ
182	    // we load 2*get<0>(blk_coord), and 2*get<0>(blk_coord) + 1
183	    ThrMMA mma_qk = typename CollectiveMmaQK::TiledMma{}.get_slice(0);
184	    Tensor mQ_qdl_p = params.tma_load_q.get_tma_tensor(select<0,2,3>(problem_shape_qk));
185	
186	    int q_offs_0 = 0;
187	
188	    if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
189	      auto cumulative_length_q = get<0>(params_problem_shape).cumulative_length;
190	      if (cumulative_length_q != nullptr) {
191	        q_offs_0 = cumulative_length_q[get<2,1>(blk_coord_q)];
192	        get<2,1>(blk_coord_q) = 0;
193	      }
194	    }
195	
196	    Tensor mQ_qdl = domain_offset(make_coord(q_offs_0, _0{}, make_coord(_0{}, _0{})), mQ_qdl_p);
197	
198	    Tensor gQ_qdl = local_tile(mQ_qdl, TileShapeQK{}, make_coord(_, _, _), Step<_1, X, _1>{});
199	    Tensor tSgQ_qdl = mma_qk.partition_A(gQ_qdl);
200	    Tensor sQ = make_tensor(make_smem_ptr(storage.smem_q.data()), SmemLayoutQ{});
201	    auto [tQgQ_qdl, tQsQ] = tma_partition(
202	      params.tma_load_q, _0{}, make_layout(_1{}), 
203	      group_modes<0,3>(sQ), group_modes<0,3>(tSgQ_qdl)
204	    );
205	    Tensor tQgQ = tQgQ_qdl(_, _, _0{}, get<2>(blk_coord_q));
206	
207	    // compute gK, sK
208	    Tensor mK_kdl_p = params.tma_load_k.get_tma_tensor(select<1,2,3>(problem_shape_qk));
209	
210	    int kv_offs_0 = 0;
211	
212	    if constexpr (is_variable_length_v<tuple_element_t<1, ParamsProblemShape>>) {
213	      auto cumulative_length = get<1>(params_problem_shape).cumulative_length;
214	      if (cumulative_length != nullptr) {
215	        kv_offs_0 = cumulative_length[get<2,1>(blk_coord_kv)];
216	        get<2,1>(blk_coord_kv) = 0;
217	      }
218	    }
219	
220	    Tensor mK_kdl = domain_offset(make_coord(kv_offs_0, _0{}, make_coord(_0{}, _0{})), mK_kdl_p);
221	
222	    Tensor gK_kdl = local_tile(mK_kdl, TileShapeQK{}, make_coord(_, _, _), Step<X, _1, _1>{});
223	    Tensor tSgK_kdl = mma_qk.partition_B(gK_kdl);
224	    Tensor sK = make_tensor(make_smem_ptr(storage.smem_k.data()), SmemLayoutK{});
225	    auto [tKgK_kdl, tKsK] = tma_partition(
226	      params.tma_load_k, _0{}, make_layout(_1{}),
227	      group_modes<0,3>(sK), group_modes<0,3>(tSgK_kdl)
228	    );
229	    Tensor tKgK = tKgK_kdl(_, _, _0{}, get<2>(blk_coord_kv));
230	
231	    // compute gV, sV
232	    ThrMMA mma_pv = typename CollectiveMmaPV::TiledMma{}.get_slice(0);
233	    Tensor mV_dkl_p = params.tma_load_v.get_tma_tensor(select<2,1,3>(problem_shape_v));
234	
235	    Tensor mV_dkl = domain_offset(make_coord(_0{}, kv_offs_0, make_coord(_0{}, _0{})), mV_dkl_p);
236	
237	    Tensor gV_dkl = local_tile(mV_dkl, TileShapePV{}, make_coord(_, _, _), Step<X, _1, _1>{});
238	    Tensor tOgV_dkl = mma_pv.partition_B(gV_dkl);
239	    Tensor sV = make_tensor(make_smem_ptr(storage.smem_v.data()), SmemLayoutV{});
240	    auto [tVgV_dkl, tVsV] = tma_partition(
241	      params.tma_load_v, _0{}, make_layout(_1{}),
242	      group_modes<0,3>(sV), group_modes<0,3>(tOgV_dkl)
243	    );
244	    auto tVgV = tVgV_dkl(_, _0{}, _, get<2>(blk_coord_kv));
245	
246	    // blk_coord in decomposed in terms of TileShape, not TileShapeQK
247	    // As such, it needs to be transformed as
248	    // (a,b,c): a -> 2*a (Q0) 2*a+1 (Q1)
249	    //          b -> 2*a (Ki i even) 2*a+1 (Ki i odd)
250	
251	    uint32_t lane_predicate = cute::elect_one_sync();
252	
253	    // Q1
254	    int q0_index = 2 * get<0>(blk_coord_q);
255	    int q1_index = 2 * get<0>(blk_coord_q) + 1;
256	    pipeline_q.producer_acquire(pipeline_q_producer_state);
257	    if (lane_predicate) {
258	      auto tma_barrier = pipeline_q.producer_get_barrier(pipeline_q_producer_state);
259	      copy(params.tma_load_q.with(*tma_barrier, 0), tQgQ(_, q0_index), tQsQ(_, pipeline_q_producer_state.index()));
260	    }
261	    ++pipeline_q_producer_state;
262	
263	    // K1
264	    int k_index = 0;
265	    pipeline_kv.producer_acquire(pipeline_kv_producer_state);
266	    if (lane_predicate) {
267	      auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
268	      copy(params.tma_load_k.with(*tma_barrier, 0), tKgK(_, k_index), tKsK(_, pipeline_kv_producer_state.index() / 2));
269	    }
270	    ++pipeline_kv_producer_state;
271	
272	    // Q2
273	    pipeline_q.producer_acquire(pipeline_q_producer_state);
274	    if (lane_predicate) {
275	      auto tma_barrier = pipeline_q.producer_get_barrier(pipeline_q_producer_state);
276	      copy(params.tma_load_q.with(*tma_barrier, 0), tQgQ(_, q1_index), tQsQ(_, pipeline_q_producer_state.index()));
277	    }
278	    ++pipeline_q_producer_state;
279	
280	    if constexpr (cute::is_same_v<OrderLoadEpilogue, cute::true_type>) {
281	      cutlass::arch::NamedBarrier::sync((NumWarpsLoad + NumWarpsEpilogue) * NumThreadsPerWarp, 
282	                                        cutlass::arch::ReservedNamedBarriers::EpilogueBarrier);
283	    }
284	
285	    // V1
286	    pipeline_kv.producer_acquire_bytes(pipeline_kv_producer_state, TransactionBytesLoadV);
287	    if (lane_predicate) {
288	      auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
289	      copy(params.tma_load_v.with(*tma_barrier, 0), tVgV(_, k_index), tVsV(_, pipeline_kv_producer_state.index() / 2));
290	    }
291	    ++pipeline_kv_producer_state;
292	    k_index += 1;
293	
294	    // loop:
295	    mask_tile_count -= 1;
296	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
297	
298	      // Ki
299	      pipeline_kv.producer_acquire(pipeline_kv_producer_state);
300	      if (lane_predicate) {
301	        auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
302	        copy(params.tma_load_k.with(*tma_barrier, 0), tKgK(_, k_index), tKsK(_, pipeline_kv_producer_state.index() / 2));
303	
304	        // prefetch vi
305	        cute::prefetch(params.tma_load_v, tVgV(_, k_index));
306	      }
307	      ++pipeline_kv_producer_state;
308	
309	      // Vi
310	      pipeline_kv.producer_acquire_bytes(pipeline_kv_producer_state, TransactionBytesLoadV);
311	      if (lane_predicate) {
312	        auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
313	        copy(params.tma_load_v.with(*tma_barrier, 0), tVgV(_, k_index), tVsV(_, pipeline_kv_producer_state.index() / 2));
314	
315	        // prefetch ki+1
316	        if(mask_tile_count > 1) {
317	          cute::prefetch(params.tma_load_k, tKgK(_, k_index + 1));
318	        }
319	      }
320	      ++pipeline_kv_producer_state;
321	      k_index += 1;
322	    }
323	  }
324	};
325	
326	}  // namespace cutlass::fmha::collective
