235	    // blk_coord in decomposed in terms of TileShape, not TileShapeQK
236	    // As such, it needs to be transformed as
237	    // (a,b,c): a -> 2*a (Q0) 2*a+1 (Q1)
238	    //          b -> 2*a (Ki i even) 2*a+1 (Ki i odd)
239	
240	    uint32_t lane_predicate = cute::elect_one_sync();
241	
242	    // Q1
243	    int q0_index = 2 * get<0>(blk_coord_q);
244	    int q1_index = 2 * get<0>(blk_coord_q) + 1;
245	    pipeline_q.producer_acquire(pipeline_q_producer_state);
246	    if (lane_predicate) {
247	      auto tma_barrier = pipeline_q.producer_get_barrier(pipeline_q_producer_state);
248	      copy(params.tma_load_q.with(*tma_barrier, 0), tQgQ(_, q0_index), tQsQ(_, pipeline_q_producer_state.index()));
249	    }
250	    ++pipeline_q_producer_state;
251	
252	    // K1
253	    int k_index = 0;
254	    pipeline_kv.producer_acquire(pipeline_kv_producer_state);
255	    if (lane_predicate) {
256	      auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
257	      copy(params.tma_load_k.with(*tma_barrier, 0), tKgK(_, k_index), tKsK(_, pipeline_kv_producer_state.index()));
258	    }
259	    ++pipeline_kv_producer_state;
260	
261	    // Q2
262	    pipeline_q.producer_acquire(pipeline_q_producer_state);
263	    if (lane_predicate) {
264	      auto tma_barrier = pipeline_q.producer_get_barrier(pipeline_q_producer_state);
265	      copy(params.tma_load_q.with(*tma_barrier, 0), tQgQ(_, q1_index), tQsQ(_, pipeline_q_producer_state.index()));
266	    }
267	    ++pipeline_q_producer_state;
268	
269	    // V1
270	    pipeline_kv.producer_acquire(pipeline_kv_producer_state);
271	    if (lane_predicate) {
272	      auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
273	      copy(params.tma_load_v.with(*tma_barrier, 0), tVgV(_, k_index), tVsV(_, pipeline_kv_producer_state.index()));
274	    }
275	    ++pipeline_kv_producer_state;
276	    k_index += 1;
277	
278	    // loop:
279	    mask_tile_count -= 1;
280	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
281	
282	      // Ki
283	      pipeline_kv.producer_acquire(pipeline_kv_producer_state);
284	      if (lane_predicate) {
285	        auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
286	        copy(params.tma_load_k.with(*tma_barrier, 0), tKgK(_, k_index), tKsK(_, pipeline_kv_producer_state.index()));
287	      }
288	      ++pipeline_kv_producer_state;
289	
290	      // Vi
291	      pipeline_kv.producer_acquire(pipeline_kv_producer_state);
292	      if (lane_predicate) {
293	        auto tma_barrier = pipeline_kv.producer_get_barrier(pipeline_kv_producer_state);
294	        copy(params.tma_load_v.with(*tma_barrier, 0), tVgV(_, k_index), tVsV(_, pipeline_kv_producer_state.index()));
295	      }
296	      ++pipeline_kv_producer_state;
297	      k_index += 1;
298	    }
299	  }
300	};
301	
302	}  // namespace cutlass::fmha::collective
