42	#include "../collective/sm100_fmha_mla_load_tma_warpspecialized.hpp"
43	#include "../common/pipeline_mla.hpp"
44	
45	namespace cutlass::fmha::collective {
46	
47	using namespace cute;
48	
49	template<
50	  class Element_,
51	  class ElementQK_,
52	  class ElementPV_,
53	  class ComposedTileShape_,
54	  class StrideQ_,
55	  class StrideK_,
56	  class StrideV_,
57	  class Mask_,
58	  // shape here is QG K H
59	  // and referes to the two softmax warps
60	  // (2, 1, 1) means that they are stacked (best for large Q since it loads the least K/V)
61	  // (1, 2, 1) means they sit side by side (best for small Q / large K)
62	  class ThreadShape = Shape<_2, _1, _1>,
63	  class OrderLoadEpilogue = cute::false_type
64	>
65	struct Sm100MlaFwdMainloopTmaWarpspecialized {
66	
67	  using Element = Element_;
68	  using ElementQK = ElementQK_;
69	  using ElementPV = ElementPV_;
70	  using ComposedTileShape = ComposedTileShape_;
71	  using StrideQ = StrideQ_;
72	  using StrideK = StrideK_;
73	  using StrideV = StrideV_;
74	  using Mask = Mask_;
75	
76	  static constexpr int StageCountQ = 2;
77	  static constexpr int StageCountK = 1;
78	  static constexpr int StageCountV = 1;
79	  static constexpr int StageCountKV = StageCountK + StageCountV;
80	  // Support StageCountKV > 2 in the future. 
81	  static_assert(StageCountK == 1 && StageCountV == 1, "Only support StageCountK = StageCountV = 1!");
82	  static_assert(std::is_same_v<ThreadShape, Shape<_2, _1, _1>>, "Only support ThreadShape = Shape<_2, _1, _1>");
83	
84	  using ClusterShape = Shape<_1, _1, _1>;
85	
86	  static const int Alignment = 128 / sizeof_bits_v<Element>;
87	
88	  static constexpr auto  HeadDimLatent = size<2, 0>(ComposedTileShape{});
89	  static constexpr auto  HeadDimRope = size<2, 1>(ComposedTileShape{});
90	  static constexpr auto  HeadDimQK = HeadDimLatent + HeadDimRope;
91	  static constexpr auto  HeadDimPV = HeadDimLatent;
92	
93	  using TileShapeQK = decltype(shape_div(replace<2>(ComposedTileShape{}, HeadDimQK), ThreadShape{}));
94	  using TileShapePV = decltype(select<0,2,1>(shape_div(replace<2>(ComposedTileShape{}, HeadDimPV), ThreadShape{})));
95	  using TileShape = decltype(replace<2>(ComposedTileShape{}, HeadDimLatent));
96	
97	  using CollectiveMmaQK = typename cutlass::gemm::collective::CollectiveBuilder<
98	      cutlass::arch::Sm100, cutlass::arch::OpClassTensorOp,
99	      Element, StrideQ, Alignment,
100	      Element, StrideK, Alignment,
101	      ElementQK,
102	      TileShapeQK, ClusterShape, cutlass::gemm::collective::StageCount<3> /* we change it later anyways*/,
103	      cutlass::gemm::KernelTmaWarpSpecialized1SmSm100>::CollectiveOp;
104	
105	  using CollectiveMmaPV = typename cutlass::gemm::collective::CollectiveBuilder<
106	      cutlass::arch::Sm100, cutlass::arch::OpClassTensorOp,
107	      // the stride for A does not matter since we do not load from smem at all
108	      Element, StrideK, Alignment,
109	      Element, decltype(select<1,0,2>(StrideV{})), Alignment,
110	      ElementPV,
111	      TileShapePV, ClusterShape, cutlass::gemm::collective::StageCount<3> /* we change it later anyways*/,
112	      cutlass::gemm::KernelTmaWarpSpecialized1SmSm100>::CollectiveOp;
113	
114	  using SmemLayoutQ = decltype(unstageSmemLayout(typename CollectiveMmaQK::SmemLayoutA{}, Int<StageCountQ>{}));
115	  using SmemLayoutK = decltype(unstageSmemLayout(typename CollectiveMmaQK::SmemLayoutB{}, Int<StageCountK>{}));
116	  using SmemLayoutV = decltype(unstageSmemLayout(typename CollectiveMmaPV::SmemLayoutB{}, Int<StageCountV>{}));
117	
118	  using SmemStorageOneStageO = decltype(make_layout(replace<2>(TileShapePV{}, _1{})));
119	  
120	  // Since the shared memory is not sufficient if we use separate Q, K, V, and O shared memory, 
121	  // we reuse shared memory for V and O to address this problem, 
122	  // and a barrier has been added to coordinate access to shared memory.
123	  static constexpr bool IsOrderLoadEpilogue = std::is_same_v<OrderLoadEpilogue, cute::true_type>;
124	  static const int NumWarpsEpilogue = 1;
125	  static const int NumWarpsLoad = 1;
126	  
127	  struct TensorStorageQKVO {
128	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutQ>> smem_q;
129	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutK>> smem_k; 
130	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutV>> smem_o; // use as O0
131	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutV>> smem_v; // use as V0 and O1
132	  };
133	
134	  struct TensorStorageQKV {
135	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutQ>> smem_q;
136	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutK>> smem_k; 
137	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutV>> smem_v;
138	  };
139	
140	  using TensorStorage = std::conditional_t<IsOrderLoadEpilogue, TensorStorageQKVO, TensorStorageQKV>;
141	
142	  enum class TmemAllocation : uint32_t {
143	    kSizeS = 128,
144	    kSizeO = 128,
145	    kSizeP = 32,
146	    S0 = 0,
147	    S1 = S0 + kSizeS,
148	    V0 = S0,  // stats storage from softmax to correction
149	    V1 = S1,
150	    P0 = S0 + kSizeP,
151	    P1 = S1 + kSizeP,
152	    O0 = S1 + kSizeS,
153	    O1 = O0 + kSizeO,
154	    kEnd = O1 + kSizeO
155	  };
156	
157	  // indices for V0 / V1
158	  enum : int {
159	    kIdxOldRowMax = 0,
160	    kIdxNewRowMax = 1,
161	    kIdxFinalRowSum = 0,
162	    kIdxFinalRowMax = 1
163	  };
