234	  template<class ProblemShape>
235	  static Params to_underlying_arguments(
236	      ProblemShape const& problem_shape,
237	      Arguments const& args,
238	      void* workspace) {
239	
240	    float scale_softmax = args.scale_softmax;
241	    if (scale_softmax == 0.0f) {
242	      scale_softmax = 1.0f / (float) std::sqrt(get<2, 0>(problem_shape) + get<2, 1>(problem_shape));
243	    }
244	    float log2_e = static_cast<float>(std::log2(std::exp(1.0)));
245	
246	    return Params{
247	        Load::to_underlying_arguments(problem_shape, args.load, workspace),
248	        args.scale_q * args.scale_k * scale_softmax,
249	        args.scale_q * args.scale_k * log2_e * scale_softmax,
250	        args.scale_v * args.inv_scale_o
251	    };
252	  }
