275	  template<class BlkCoord, class ProblemShape>
276	  CUTLASS_DEVICE auto
277	  mma(
278	      BlkCoord const& blk_coord,
279	      Params const& params, ProblemShape const& problem_shape,
280	      TensorStorage& storage,
281	      PipelineQ& pipeline_q, typename PipelineQ::PipelineState& pipeline_q_consumer_state,
282	      PipelineKV& pipeline_kv, typename PipelineKV::PipelineState& pipeline_kv_consumer_state,
283	      PipelineS& pipeline_s0, typename PipelineS::PipelineState& pipeline_s0_producer_state,
284	      PipelineS& pipeline_s1, typename PipelineS::PipelineState& pipeline_s1_producer_state,
285	      PipelineO& pipeline_corr, typename PipelineO::PipelineState& pipeline_corr_producer_state) {
286	
287	    auto pipeline_q_release_state = pipeline_q_consumer_state;
288	    auto pipeline_kv_release_state = pipeline_kv_consumer_state;
289	
290	    int mask_tile_count = Mask{}.get_trip_count(blk_coord, TileShape{}, problem_shape);
291	
292	    typename CollectiveMmaQK::TiledMma mma_qk;
293	    ThrMMA thr_mma_qk = mma_qk.get_slice(0);
294	
295	    typename CollectiveMmaPV::TiledMma mma_pv;
296	    TiledMMA mma_pv_ts = to_tiled_mma_sm100_ts(mma_pv);
297	    ThrMMA thr_mma_pv = mma_pv_ts.get_slice(0);
298	
299	    Tensor sQ = make_tensor(make_smem_ptr(storage.smem_q.data()), SmemLayoutQ{});
300	    Tensor sK = make_tensor(make_smem_ptr(storage.smem_k.data()), SmemLayoutK{});
301	    Tensor sV = make_tensor(make_smem_ptr(storage.smem_v.data()), SmemLayoutV{});
302	
303	    Tensor tSrQ = thr_mma_qk.make_fragment_A(sQ);
304	    Tensor tSrK = thr_mma_qk.make_fragment_B(sK);
305	    Tensor tOrV = thr_mma_pv.make_fragment_B(sV);
306	
307	    // tmem layout is
308	    // S0 S1`O0 O1
309	    // sequential in memory, where S overlaps with P and V
310	
311	    Tensor tStS = partition_fragment_C(mma_qk, select<0,1>(TileShapeQK{}));
312	    Tensor tOtO = partition_fragment_C(mma_pv_ts, select<0,1>(TileShapePV{}));
313	
314	    Tensor tStS0 = tStS;
315	    tStS0.data() = tStS.data().get() + uint32_t(TmemAllocation::S0);
316	    Tensor tStS1 = tStS;
317	    tStS1.data() = tStS.data().get() + uint32_t(TmemAllocation::S1);
318	
319	    Tensor tOtO0 = tOtO;
320	    tOtO0.data() = tOtO.data().get() + uint32_t(TmemAllocation::O0);
321	    Tensor tOtO1 = tOtO;
322	    tOtO1.data() = tOtO.data().get() + uint32_t(TmemAllocation::O1);
323	
324	    Tensor sP = make_tensor(make_smem_ptr((Element*)nullptr), typename CollectiveMmaPV::SmemLayoutA{});
325	    Tensor tOrP = thr_mma_pv.make_fragment_A(sP)(_, _, _, _0{});  // slice out staging
326	
327	    Tensor tOrP0 = tOrP;
328	    tOrP0.data() = tOrP0.data().get() + uint32_t(TmemAllocation::P0);
329	    Tensor tOrP1 = tOrP;
330	    tOrP1.data() = tOrP1.data().get() + uint32_t(TmemAllocation::P1);
331	
332	    int k_index = 0;
333	    int v_index = 0;
334	    int q_index = 0;
335	
336	    // wait for Q1
337	    q_index = pipeline_q_consumer_state.index();
338	    pipeline_q.consumer_wait(pipeline_q_consumer_state);
339	    ++pipeline_q_consumer_state;
340	
341	    Tensor tSrQ0 = tSrQ(_,_,_,q_index);
342	
343	
344	    // wait for K1
345	    k_index = pipeline_kv_consumer_state.index();
346	    pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
347	    ++pipeline_kv_consumer_state;
348	
349	    // gemm Q1 * K1 -> S1
350	    pipeline_s0.producer_acquire(pipeline_s0_producer_state);
351	
352	    gemm_zero_acc(mma_qk, tSrQ0, tSrK(_,_,_,k_index / 2), tStS0);
353	
354	    pipeline_s0.producer_commit(pipeline_s0_producer_state);
355	    ++pipeline_s0_producer_state;
356	
357	    // release K1
358	    if constexpr (get<1>(ThreadShape{}) > 1) {
359	      pipeline_kv.consumer_release(pipeline_kv_release_state);
360	      ++pipeline_kv_release_state;
361	    }
362	
363	    // wait for Q2
364	    if constexpr (get<0>(ThreadShape{}) > 1 || get<2>(ThreadShape{}) > 1) {
365	      q_index = pipeline_q_consumer_state.index();
366	      pipeline_q.consumer_wait(pipeline_q_consumer_state);
367	      ++pipeline_q_consumer_state;
368	    }
369	
370	    Tensor tSrQ1 = tSrQ(_,_,_,q_index);
371	
372	    if constexpr (get<1>(ThreadShape{}) > 1) {
373	      k_index = pipeline_kv_consumer_state.index();
374	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
375	      ++pipeline_kv_consumer_state;
376	    }
377	
378	    pipeline_s1.producer_acquire(pipeline_s1_producer_state);
379	
380	    // gemm Q2 * K1 -> S2
381	    gemm_zero_acc(mma_qk, tSrQ1, tSrK(_,_,_,k_index / 2), tStS1);
382	
383	    pipeline_s1.producer_commit(pipeline_s1_producer_state);
384	    ++pipeline_s1_producer_state;
385	
386	    // release K1
387	    pipeline_kv.consumer_release(pipeline_kv_release_state);
388	    ++pipeline_kv_release_state;
389	
390	    // wait for V1
391	    v_index = pipeline_kv_consumer_state.index();
392	    pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
393	    ++pipeline_kv_consumer_state;
394	
395	    // this acquire returns the ownership of all of S0 to the mma warp
396	    // including the P0 part
397	    // acquire corr first to take it out of the critical
398	    // path since softmax takes longer
399	    pipeline_corr.producer_acquire(pipeline_corr_producer_state);
400	    pipeline_s0.producer_acquire(pipeline_s0_producer_state);
401	
402	    // gemm P1 * V1 -> O1
403	    gemm_zero_acc(mma_pv_ts, tOrP0, tOrV(_,_,_,v_index / 2), tOtO0);
404	
405	    pipeline_corr.producer_commit(pipeline_corr_producer_state);
406	    ++pipeline_corr_producer_state;
407	
408	      if constexpr (get<1>(ThreadShape{}) > 1) {
409	      pipeline_kv.consumer_release(pipeline_kv_release_state);
410	      ++pipeline_kv_release_state;
411	    }
412	
413	    mma_pv_ts.accumulate_ = UMMA::ScaleOut::Zero;
414	
415	    // loop:
416	    mask_tile_count -= 1;
417	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
418	
419	      // wait for Ki
420	      k_index = (pipeline_kv_consumer_state.index());
421	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
422	      ++pipeline_kv_consumer_state;
423	
424	      // gemm Q1 * Ki -> S1
425	      gemm_zero_acc(mma_qk, tSrQ0, tSrK(_,_,_,k_index / 2), tStS0);
426	
427	      pipeline_s0.producer_commit(pipeline_s0_producer_state);
428	      ++pipeline_s0_producer_state;
429	
430	      if constexpr (get<1>(ThreadShape{}) > 1) {
431	        pipeline_kv.consumer_release(pipeline_kv_release_state);
432	        ++pipeline_kv_release_state;
433	      }
434	
435	      // gemm P2 * V(i-1) -> O2
436	      if constexpr (get<1>(ThreadShape{}) > 1) {
437	        v_index = pipeline_kv_consumer_state.index();
438	        pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
439	        ++pipeline_kv_consumer_state;
440	      }
441	
442	      pipeline_corr.producer_acquire(pipeline_corr_producer_state);
443	      pipeline_s1.producer_acquire(pipeline_s1_producer_state);
444	
445	      gemm_reset_zero_acc(mma_pv_ts, tOrP1, tOrV(_,_,_,v_index / 2), tOtO1);
446	
447	      pipeline_corr.producer_commit(pipeline_corr_producer_state);
448	      ++pipeline_corr_producer_state;
449	
450	      // release V(i-1)
451	      pipeline_kv.consumer_release(pipeline_kv_release_state);
452	      ++pipeline_kv_release_state;
453	
454	      if constexpr (get<1>(ThreadShape{}) > 1) {
455	        k_index = (pipeline_kv_consumer_state.index());
456	        pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
457	        ++pipeline_kv_consumer_state;
458	      }
459	
460	      // gemm Q2 * Ki -> S2
461	      gemm_zero_acc(mma_qk, tSrQ1, tSrK(_,_,_,k_index / 2), tStS1);
462	
463	      pipeline_s1.producer_commit(pipeline_s1_producer_state);
464	      ++pipeline_s1_producer_state;
465	
466	      // release Ki
467	      pipeline_kv.consumer_release(pipeline_kv_release_state);
468	      ++pipeline_kv_release_state;
469	
470	      // wait for Vi
471	      v_index = (pipeline_kv_consumer_state.index());
472	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
473	      ++pipeline_kv_consumer_state;
474	
475	      // gemm P1 * Vi -> O1
476	      pipeline_corr.producer_acquire(pipeline_corr_producer_state);
477	
478	      pipeline_s0.producer_acquire(pipeline_s0_producer_state);
479	
480	      gemm_reset_zero_acc(mma_pv_ts, tOrP0, tOrV(_,_,_,v_index / 2), tOtO0);
481	
482	      pipeline_corr.producer_commit(pipeline_corr_producer_state);
483	      ++pipeline_corr_producer_state;
484	
485	      if constexpr (get<1>(ThreadShape{}) > 1) {
486	        pipeline_kv.consumer_release(pipeline_kv_release_state);
487	        ++pipeline_kv_release_state;
488	      }
489	    }
490	
491	    // release Q1
492	    pipeline_q.consumer_release(pipeline_q_release_state);
493	    ++pipeline_q_release_state;
494	
495	    // release Q2
496	    if constexpr (get<0>(ThreadShape{}) > 1) {
497	      pipeline_q.consumer_release(pipeline_q_release_state);
498	      ++pipeline_q_release_state;
499	    }
500	
501	    // wait for Vi
502	    if constexpr (get<1>(ThreadShape{}) > 1) {
503	      v_index = pipeline_kv_consumer_state.index();
504	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
505	      ++pipeline_kv_consumer_state;
506	    }
507	
508	    // gemm P2 * Vi -> O2
509	    pipeline_corr.producer_acquire(pipeline_corr_producer_state);
510	    pipeline_s1.producer_acquire(pipeline_s1_producer_state);
511	
512	    gemm_reset_zero_acc(mma_pv_ts, tOrP1, tOrV(_,_,_,v_index / 2), tOtO1);
513	
514	    pipeline_corr.producer_commit(pipeline_corr_producer_state);
515	    ++pipeline_corr_producer_state;
516	
517	    // release Vi
518	    pipeline_kv.consumer_release(pipeline_kv_release_state);
519	    ++pipeline_kv_release_state;
520	
521	    pipeline_s0.producer_commit(pipeline_s0_producer_state);
522	    ++pipeline_s0_producer_state;
523	
524	    pipeline_s1.producer_commit(pipeline_s1_producer_state);
525	    ++pipeline_s1_producer_state;
526	
527	    // T0 S00 B1, T0 S10 B1, T0 S00 B2, T0 S01 B1, T0 S10 B2, T0 S11 B1, T0 S01 B2, T1 S00 B1, T0 S11 B2, ...
528	    // Q1 * K1  , Q2 * K1  , S11 * V1 , Q1 * K2  , S21 * V1  , Q2 * K2 , S12 * V2 , Q1 * K3  , S22 * K2 , ...
529	  }
530	
531	  template<bool need_mask, class Stage, class BlkCoord, class CoordTensor, class ProblemShape>
532	  CUTLASS_DEVICE auto
533	  softmax_step(
534	      bool need_apply_mask,
535	      float& row_max, float& row_sum,
536	      Stage stage, bool final_call,
537	      BlkCoord const& blk_coord, CoordTensor const& cS,
538	      Params const& params, ProblemShape const& problem_shape,
539	      PipelineS& pipeline_s, typename PipelineS::PipelineState& pipeline_s_consumer_state,
540	      PipelineC& pipeline_c, typename PipelineC::PipelineState& pipeline_c_producer_state,
541	      OrderBarrierSoftmax& order_s) {
542	
543	    Tensor tScS = typename CollectiveMmaQK::TiledMma{}.get_slice(0).partition_C(cS);
544	
545	    Tensor tStS = partition_fragment_C(typename CollectiveMmaQK::TiledMma{}, select<0,1>(TileShapeQK{}));
546	    tStS.data() = uint32_t(stage == _0{} ? TmemAllocation::S0 : TmemAllocation::S1);
547	
548	    Tensor tStS_v = tStS.compose(make_layout(make_shape(_128{}, _2{})));
549	    tStS_v.data() = uint32_t(stage == _0{} ? TmemAllocation::V0 : TmemAllocation::V1);
550	    Tensor tScS_v = tScS.compose(make_layout(make_shape(_128{}, _2{})));
551	
552	    auto tilePlikeFP32 = size<1>(TileShapeQK{}) / Int<sizeof(float)>{} * Int<sizeof(Element)>{};
553	    Tensor tStS_P = tStS.compose(make_layout(make_shape(_128{}, tilePlikeFP32)));
554	    tStS_P.data() = warp_uniform(uint32_t(stage == _0{} ? TmemAllocation::P0 : TmemAllocation::P1));
555	    Tensor tScS_P = tScS.compose(make_layout(make_shape(_128{}, tilePlikeFP32)));
556	
557	    // Each thread owns a single row
558	    using TMEM_LOAD = SM100_TMEM_LOAD_32dp32b32x; // 4x32 threads with 128 cols of 32b elem
559	    using TMEM_STORE = SM100_TMEM_STORE_32dp32b32x;  // 4x32 threads with 128 cols of 8b elem
560	    using TMEM_STORE_V = SM100_TMEM_STORE_32dp32b2x;   // 4x32 threads with 2 cols of 32b elem
561	
562	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
563	
564	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tStS);
565	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
566	
567	    Tensor tTMEM_LOADtS = thr_tmem_load.partition_S(tStS);
568	    Tensor tTMEM_LOADcS = thr_tmem_load.partition_D(tScS);
569	
570	    auto tiled_tmem_storev = make_tmem_copy(TMEM_STORE_V{}, tStS_v);
571	    auto thr_tmem_storev  = tiled_tmem_storev.get_slice(thread_idx);
572	
573	    Tensor tTMEM_STOREVtS = thr_tmem_storev.partition_D(tStS_v);
574	    Tensor tTMEM_STOREVcS = thr_tmem_storev.partition_S(tScS_v);
575	
576	    auto tiled_tmem_store = make_tmem_copy(TMEM_STORE{}, tStS_P);
577	    auto thr_tmem_store  = tiled_tmem_store.get_slice(thread_idx);
578	
579	    Tensor tTMEM_STOREtS_x4 = thr_tmem_store.partition_D(tStS_P);
580	    tTMEM_STOREtS_x4.data() = warp_uniform(tTMEM_STOREtS_x4.data().get());
581	    Tensor tTMEM_STOREcS = thr_tmem_store.partition_S(tScS_P);
582	
583	    // wait on tensor core pipe
584	    pipeline_s.consumer_wait(pipeline_s_consumer_state);
585	
586	    // read all of S from tmem into reg mem
587	    Tensor tTMEM_LOADrS = make_tensor<ElementQK>(shape(tTMEM_LOADcS));
588	    copy(tiled_tmem_load, tTMEM_LOADtS, tTMEM_LOADrS);
589	
590	    if constexpr (need_mask) {
591	      if(need_apply_mask) {
592	        Mask{}.apply_mask(tTMEM_LOADrS, tTMEM_LOADcS, problem_shape);
593	      }
594	    }
595	
596	    ElementQK old_row_max = row_max;
597	    {
598	      // compute rowmax
599	      float row_max_0 = row_max;
600	      float row_max_1 = row_max;
601	      float row_max_2 = row_max;
602	      float row_max_3 = row_max;
603	      CUTLASS_PRAGMA_UNROLL
604	      for (int i = 0; i < size(tTMEM_LOADrS); i += 4) {
605	        row_max_0  = ::fmax(row_max_0, tTMEM_LOADrS(i));
606	        row_max_1 = ::fmax(row_max_1, tTMEM_LOADrS(i+1));
607	        row_max_2 = ::fmax(row_max_2, tTMEM_LOADrS(i+2));
608	        row_max_3 = ::fmax(row_max_3, tTMEM_LOADrS(i+3));
609	      }
610	      row_max = ::fmax(row_max_0, row_max_1);
611	      row_max = ::fmax(row_max, row_max_2);
612	      row_max = ::fmax(row_max, row_max_3);
613	    }
614	
615	    ElementQK row_max_safe = row_max == -INFINITY ? 0 : row_max;
616	
617	    Tensor tTMEM_STOREVrS = make_tensor<ElementQK>(shape(tTMEM_STOREVcS));
618	    tTMEM_STOREVrS(kIdxOldRowMax) = old_row_max;
619	    tTMEM_STOREVrS(kIdxNewRowMax) = row_max_safe;
620	    copy(tiled_tmem_storev, tTMEM_STOREVrS, tTMEM_STOREVtS);
621	
622	    pipeline_c.producer_commit(pipeline_c_producer_state);
623	    ++pipeline_c_producer_state;
624	
625	    // notify correction wg that they are ready (might need addtl ordering between S0 and S1 WG's)
626	
627	    ElementQK scale = params.scale_softmax_log2;
628	    ElementQK row_max_scale = row_max_safe * scale;
629	
630	    float2 scale_fp32x2 = make_float2(scale, scale);
631	    float2 minus_row_max_scale_fp32x2 = make_float2(-row_max_scale, -row_max_scale);
632	
633	    Tensor tTMEM_STORErS_x4 = make_tensor<uint32_t>(shape(tTMEM_STOREcS));
634	
635	    constexpr int kConversionsPerStep = 2;
636	
637	    Tensor tTMEM_STORErS_x4_e = recast<Array<Element, kConversionsPerStep>>(tTMEM_STORErS_x4);
638	
639	    NumericArrayConverter<Element, ElementQK, kConversionsPerStep> convert;
640	
641	    constexpr int kReleasePipeCount = 10;  // must be multiple of 2
642	
643	    order_s.wait();
644	
645	    CUTLASS_PRAGMA_UNROLL
646	    for (int i = 0; i < size(tTMEM_LOADrS); i += 2) {
647	      float2 in = make_float2(
648	        tTMEM_LOADrS(i + 0),
649	        tTMEM_LOADrS(i + 1)
650	      );
651	      float2 out;
652	      cute::fma(out, scale_fp32x2, in, minus_row_max_scale_fp32x2);
653	      tTMEM_LOADrS(i + 0) = out.x;
654	      tTMEM_LOADrS(i + 1) = out.y;
655	
656	      tTMEM_LOADrS(i+0) = ::exp2f(tTMEM_LOADrS(i+0));
657	      tTMEM_LOADrS(i+1) = ::exp2f(tTMEM_LOADrS(i+1));
658	
659	      Array<ElementQK, kConversionsPerStep> in_conv;
660	      CUTLASS_PRAGMA_UNROLL
661	      for (int j = 0; j < kConversionsPerStep; j++) {
662	        in_conv[j] = tTMEM_LOADrS(i + j);
663	      }
664	      tTMEM_STORErS_x4_e[i / kConversionsPerStep] = convert(in_conv);
665	
666	
667	      if (i == size(tTMEM_LOADrS) - kReleasePipeCount) {
668	        order_s.arrive();
669	      }
670	
671	      // this prevents register spills in fp16
672	      if constexpr (size<2>(tTMEM_STORErS_x4) == _2{}) {
673	        if (i == size(tTMEM_LOADrS) - 6) {
674	          copy(tiled_tmem_store, tTMEM_STORErS_x4(_, _, 0), tTMEM_STOREtS_x4(_, _, 0));
675	        }
676	      }
677	    }
678	
679	    // tmem_store(reg_S8) -> op_P
680	    CUTE_STATIC_ASSERT_V(size<2>(tTMEM_STORErS_x4) <= _2{});
681	    CUTE_STATIC_ASSERT_V(size<1>(tTMEM_STORErS_x4) == _1{});
682	    copy(tiled_tmem_store, tTMEM_STORErS_x4(_, _, size<2>(tTMEM_STORErS_x4) - 1), tTMEM_STOREtS_x4(_, _, size<2>(tTMEM_STORErS_x4) - 1));
683	
684	    cutlass::arch::fence_view_async_tmem_store();
685	
686	    // notify tensor core warp that P is ready
687	    pipeline_s.consumer_release(pipeline_s_consumer_state);
688	    ++pipeline_s_consumer_state;
689	
690	    pipeline_c.producer_acquire(pipeline_c_producer_state);
691	
692	    ElementQK acc_scale = 0.5f * ::exp2f(scale * (old_row_max - row_max_safe));
693	    row_sum *= acc_scale;
694	    // row_sum = sum(reg_S)
695	    float2 local_row_sum_f32x2 = make_float2(row_sum, row_sum);
696	    float2 local_row_sum_1 = make_float2(0, 0);
697	    float2 local_row_sum_2 = make_float2(0, 0);
698	    float2 local_row_sum_3 = make_float2(0, 0);
699	
700	    CUTLASS_PRAGMA_UNROLL
701	    for (int i = 0; i < size(tTMEM_LOADrS); i += 8) {
702	      // row_sum += tTMEM_LOADrS(i);
703	      float2 in = make_float2(tTMEM_LOADrS(i), tTMEM_LOADrS(i+1));
704	      cute::add(local_row_sum_f32x2, local_row_sum_f32x2, in);
705	
706	      in = make_float2(tTMEM_LOADrS(i+2), tTMEM_LOADrS(i+2+1));
707	      cute::add(local_row_sum_1, local_row_sum_1, in);
708	
709	      in = make_float2(tTMEM_LOADrS(i+4), tTMEM_LOADrS(i+4+1));
710	      cute::add(local_row_sum_2, local_row_sum_2, in);
711	
712	      in = make_float2(tTMEM_LOADrS(i+6), tTMEM_LOADrS(i+6+1));
713	      cute::add(local_row_sum_3, local_row_sum_3, in);
714	    }
715	
716	    cute::add(local_row_sum_f32x2, local_row_sum_f32x2, local_row_sum_1);
717	    cute::add(local_row_sum_2, local_row_sum_2, local_row_sum_3);
718	    cute::add(local_row_sum_f32x2, local_row_sum_f32x2, local_row_sum_2);
719	    float local_row_sum = local_row_sum_f32x2.x + local_row_sum_f32x2.y;
720	
721	    row_sum = local_row_sum;
722	
723	    if (final_call) {
724	      // re-acquire the S part in the final step
725	      pipeline_s.consumer_wait(pipeline_s_consumer_state);
726	
727	      Tensor tTMEM_STOREVrS = make_tensor<ElementQK>(shape(tTMEM_STOREVcS));
728	      tTMEM_STOREVrS(kIdxFinalRowMax) = row_max;
729	      tTMEM_STOREVrS(kIdxFinalRowSum) = row_sum;
730	      copy(tiled_tmem_storev, tTMEM_STOREVrS, tTMEM_STOREVtS);
731	    }
732	  }
