734	  template<class Stage, class BlkCoord, class ProblemShape>
735	  CUTLASS_DEVICE auto
736	  softmax(
737	      Stage stage,
738	      BlkCoord const& blk_coord,
739	      Params const& params, ProblemShape const& problem_shape,
740	      PipelineS& pipeline_s, typename PipelineS::PipelineState& pipeline_s_consumer_state,
741	      PipelineC& pipeline_c, typename PipelineC::PipelineState& pipeline_c_producer_state,
742	      OrderBarrierSoftmax& order_s) {
743	    const int mask_trip_count = Mask{}.get_masked_trip_count(blk_coord, TileShape{}, problem_shape);
744	    const int total_trip_count = Mask{}.get_trip_count(blk_coord, TileShape{}, problem_shape);
745	    int trip_idx = total_trip_count;
746	
747	    ElementQK row_max = -INFINITY;
748	    ElementQK row_sum = 0;
749	
750	    Tensor cS_base = make_identity_tensor(select<0,1>(TileShapeQK{}));
751	    auto logical_offset = make_coord(
752	        get<0>(blk_coord) * get<0>(TileShape{}) + (stage % get<0>(ThreadShape{})) * get<0>(TileShapeQK{}),
753	        0 + (stage % get<1>(ThreadShape{})) * get<1>(TileShapeQK{})
754	    );
755	    Tensor cS = domain_offset(logical_offset, cS_base);
756	
757	    pipeline_c.producer_acquire(pipeline_c_producer_state);
758	    
759	    constexpr bool NeedMask = !std::is_same_v<Mask, NoMask>;
760	
761	    CUTLASS_PRAGMA_NO_UNROLL
762	    for (; trip_idx > 0; trip_idx -= 1) {
763	      softmax_step<NeedMask /* need_mask */>(
764	          trip_idx <= mask_trip_count,
765	          row_max, row_sum, stage,
766	          trip_idx == 1,
767	          blk_coord, cS, params, problem_shape,
768	          pipeline_s, pipeline_s_consumer_state,
769	          pipeline_c, pipeline_c_producer_state,
770	          order_s
771	      );
772	
773	      cS.data() = cS.data() + E<1>{} * get<1>(ThreadShape{}) * get<1>(TileShapeQK{});
774	    }
775	
776	    pipeline_c.producer_commit(pipeline_c_producer_state);
777	    ++pipeline_c_producer_state;
778	
779	    pipeline_c.producer_acquire(pipeline_c_producer_state);
780	    // empty step to sync against pipe s
781	    pipeline_s.consumer_release(pipeline_s_consumer_state);
782	    ++pipeline_s_consumer_state;
783	  }
