785	  template<class Stage, class TensorO>
786	  CUTLASS_DEVICE auto
787	  correction_epilogue(
788	      float scale,
789	      Stage stage,
790	      TensorO const& sO_01) {
791	
792	    using ElementOut = typename TensorO::value_type;
793	
794	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
795	
796	    Tensor sO = sO_01(_,_,stage);
797	
798	    // As opposed to the softmax, we do not have enough registers here
799	    // to load all of the values (for tile kv = 128), so we loop
800	    // good values would be either 32 or 64
801	    constexpr int kCorrectionTileSize = 32 / sizeof(ElementOut);
802	
803	    using TMEM_LOAD = std::conditional_t<kCorrectionTileSize == 32, SM100_TMEM_LOAD_32dp32b32x, SM100_TMEM_LOAD_32dp32b16x>;  // 4x32 threads with 64 cols of 32b elem
804	
805	    typename CollectiveMmaPV::TiledMma mma;
806	    Tensor cO = make_identity_tensor(select<0,1>(TileShapePV{}));
807	    Tensor tOtO = partition_fragment_C(mma, select<0,1>(TileShapePV{}));
808	    Tensor tOcO = mma.get_slice(0).partition_C(cO);
809	    Tensor tOsO = mma.get_slice(0).partition_C(sO);
810	
811	    Tensor tOtO_i = logical_divide(tOtO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
812	    Tensor tOcO_i = logical_divide(tOcO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
813	    Tensor tOsO_i = logical_divide(tOsO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
814	
815	    if constexpr (decltype(stage == _0{})::value) {
816	      tOtO_i.data() = tOtO_i.data().get() + uint32_t(TmemAllocation::O0);
817	    }
818	    else {
819	      static_assert(decltype(stage == _1{})::value, "stage is either 0 or 1");
820	      tOtO_i.data() = tOtO_i.data().get() + uint32_t(TmemAllocation::O1);
821	    }
822	
823	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tOtO_i(make_coord(_, _), _0{}));
824	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
825	
826	    Tensor tTMEM_LOADtO = thr_tmem_load.partition_S(tOtO_i(make_coord(_, _), _));
827	    Tensor tTMEM_LOADcO = thr_tmem_load.partition_D(tOcO_i(make_coord(_, _), _));
828	    Tensor tTMEM_LOADsO = thr_tmem_load.partition_D(tOsO_i(make_coord(_, _), _));
829	
830	    float2 scale_f32x2 = make_float2(scale, scale);
831	
832	    // loop:
833	    //   TMEM_LOAD, FMUL2 scale, TMEM_STORE
834	    CUTLASS_PRAGMA_UNROLL
835	    for (int i = 0; i < get<2>(TileShape{}) / kCorrectionTileSize; i++) {
836	      Tensor tTMEM_LOADtO_i = tTMEM_LOADtO(_, _0{}, _0{}, i);
837	      Tensor tTMEM_LOADsO_i = tTMEM_LOADsO(_, _0{}, _0{}, i);
838	
839	      Tensor tTMrO = make_tensor<ElementPV>(shape(tTMEM_LOADcO(_, _0{}, _0{}, i)));
840	
841	      copy(tiled_tmem_load, tTMEM_LOADtO_i, tTMrO);
842	
843	#ifndef ONLY_SOFTMAX
844	      CUTLASS_PRAGMA_UNROLL
845	      for (int j = 0; j < size(tTMrO); j += 2) {
846	        float2 in = make_float2(tTMrO(j), tTMrO(j+1));
847	        float2 out;
848	        cute::mul(out, scale_f32x2, in);
849	        tTMrO(j) = out.x;
850	        tTMrO(j+1) = out.y;
851	      }
852	#endif
853	
854	      constexpr int N = 4 / sizeof(ElementOut);
855	      NumericArrayConverter<ElementOut, ElementPV, N> convert;
856	
857	      Tensor tSMrO = make_tensor_like<ElementOut>(tTMrO);
858	
859	      Tensor tCs = recast<decltype(convert)::source_type>(tTMrO);
860	      Tensor tCd = recast<decltype(convert)::result_type>(tSMrO);
861	
862	      CUTLASS_PRAGMA_UNROLL
863	      for (int j = 0; j < size(tCs); j++) {
864	        tCd(j) = convert.convert(tCs(j));
865	      }
866	
867	      Tensor tSMsO_i = recast<uint32_t>(tTMEM_LOADsO_i);
868	      Tensor tSMrO_i = recast<uint32_t>(tSMrO);
869	
870	      copy(AutoVectorizingCopyWithAssumedAlignment<128>{}, tSMrO_i, tSMsO_i);
871	    }
872	
873	    cutlass::arch::fence_view_async_shared();
874	  }
875	
876	  CUTLASS_DEVICE auto
877	  correction_rescale(
878	      float scale,
879	      uint32_t tmem_O) {
880	
881	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
882	
883	    // As opposed to the softmax, we do not have enough registers here
884	    // to load all of the values (for tile kv = 128), so we loop
885	    // good values would be either 32 or 64
886	    constexpr int kCorrectionTileSize = 16;
887	
888	    using TMEM_LOAD = SM100_TMEM_LOAD_32dp32b16x;  // 4x32 threads with 64 cols of 32b elem
889	    using TMEM_STORE = SM100_TMEM_STORE_32dp32b16x;  // 4x32 threads with 64 cols of 32b elem
890	
891	    typename CollectiveMmaPV::TiledMma mma;
892	    Tensor cO = make_identity_tensor(select<0,1>(TileShapePV{}));
893	    Tensor tOtO = partition_fragment_C(mma, select<0,1>(TileShapePV{}));
894	    Tensor tOcO = mma.get_slice(0).partition_C(cO);
895	
896	    Tensor tOtO_i = tOtO.compose(make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
897	    Tensor tOcO_i = tOcO.compose(make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
898	
899	    tOtO_i.data() = tOtO_i.data().get() + tmem_O;
900	
901	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tOtO_i);
902	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
903	    auto tiled_tmem_store = make_tmem_copy(TMEM_STORE{}, tOtO_i);
904	    auto thr_tmem_store   = tiled_tmem_store.get_slice(thread_idx);
905	
906	    Tensor tTMEM_LOADtO = thr_tmem_load.partition_S(tOtO_i);
907	    Tensor tTMEM_LOADcO = thr_tmem_load.partition_D(tOcO_i);
908	    Tensor tTMEM_STOREtO = thr_tmem_store.partition_D(tOtO_i);
909	    Tensor tTMEM_STOREcO = thr_tmem_store.partition_S(tOcO_i);
910	    static_assert(shape(tTMEM_STOREcO) == shape(tTMEM_LOADcO));
911	
912	    float2 scale_f32x2 = make_float2(scale, scale);
913	
914	    Tensor tTMrO = make_tensor<ElementPV>(make_shape(shape(tTMEM_LOADcO), Int<128 / kCorrectionTileSize>{}));
915	
916	    auto copy_in = [&](int i) {
917	      Tensor tTMEM_LOADtO_i = tTMEM_LOADtO;
918	      tTMEM_LOADtO_i.data() = tTMEM_LOADtO_i.data().get() + uint32_t(i * kCorrectionTileSize);
919	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
920	      copy(tiled_tmem_load, tTMEM_LOADtO_i, tTMrO_i);
921	    };
922	
923	    auto copy_out = [&](int i) {
924	      Tensor tTMEM_STOREtO_i = tTMEM_STOREtO;
925	      tTMEM_STOREtO_i.data() = tTMEM_STOREtO_i.data().get() + uint32_t(i * kCorrectionTileSize);
926	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
927	      copy(tiled_tmem_store, tTMrO_i, tTMEM_STOREtO_i);
928	    };
929	
930	    // sequence: LLMSLMSLMSS
931	
932	    // loop:
933	    //   TMEM_LOAD, FMUL2 scale, TMEM_STORE
934	    copy_in(0);
935	
936	    constexpr int count = get<2>(TileShape{}) / kCorrectionTileSize;
937	
938	    CUTLASS_PRAGMA_UNROLL
939	    for (int i = 0; i < count; i++) {
940	      if (i != count - 1) {
941	        copy_in(i+1);
942	      }
943	
944	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
945	      CUTLASS_PRAGMA_UNROLL
946	      for (int j = 0; j < size(tTMrO_i); j += 2) {
947	        float2 in = make_float2(tTMrO_i(j), tTMrO_i(j+1));
948	        float2 out;
949	        cute::mul(out, scale_f32x2, in);
950	        tTMrO_i(j) = out.x;
951	        tTMrO_i(j+1) = out.y;
952	      }
953	
954	      copy_out(i);
955	    }
956	  }
957	
958	  template<
959	    class BlkCoord, class ProblemShape, class ParamsProblemShape,
960	    class TensorStorageEpi, class CollectiveEpilogue
961	  >
962	  CUTLASS_DEVICE auto
963	  correction(
964	      BlkCoord const& blk_coord,
965	      Params const& params, ProblemShape const& problem_shape,
966	      ParamsProblemShape const& params_problem_shape,
967	      TensorStorageEpi& shared_storage_epi,
968	      PipelineC& pipeline_s0_c, typename PipelineC::PipelineState& pipeline_s0_c_consumer_state,
969	      PipelineC& pipeline_s1_c, typename PipelineC::PipelineState& pipeline_s1_c_consumer_state,
970	      PipelineO& pipeline_o, typename PipelineO::PipelineState& pipeline_o_consumer_state,
971	      PipelineE& pipeline_epi, typename PipelineE::PipelineState& pipeline_epi_producer_state,
972	      CollectiveEpilogue& epilogue) {
973	
974	    int mask_tile_count = Mask{}.get_trip_count(blk_coord, TileShape{}, problem_shape);
975	
976	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
977	
978	    Tensor tStS = partition_fragment_C(typename CollectiveMmaQK::TiledMma{}, select<0,1>(TileShapeQK{}));
979	
980	    Tensor cS = make_identity_tensor(select<0,1>(TileShapeQK{}));
981	    Tensor tScS = typename CollectiveMmaQK::TiledMma{}.get_slice(0).partition_C(cS);
982	
983	    Tensor tStS_v = tStS.compose(make_layout(make_shape(_128{}, _2{})));
984	    Tensor tScS_v = tScS.compose(make_layout(make_shape(_128{}, _2{})));
985	
986	    using TMEM_LOAD_V = SM100_TMEM_LOAD_32dp32b2x;   // 4x32 threads with 2 cols of 32b elem
987	
988	    auto tiled_tmem_loadv = make_tmem_copy(TMEM_LOAD_V{}, tStS_v);
989	    auto thr_tmem_loadv  = tiled_tmem_loadv.get_slice(thread_idx);
990	
991	    Tensor tTMEM_LOADVtS = thr_tmem_loadv.partition_S(tStS_v);
992	    Tensor tTMEM_LOADVcS = thr_tmem_loadv.partition_D(tScS_v);
993	
994	    Tensor tTMEM_LOADVtS0 = tTMEM_LOADVtS;
995	    tTMEM_LOADVtS0.data() = tTMEM_LOADVtS0.data().get() + uint32_t(TmemAllocation::V0);
996	    Tensor tTMEM_LOADVtS1 = tTMEM_LOADVtS;
997	    tTMEM_LOADVtS1.data() = tTMEM_LOADVtS1.data().get() + uint32_t(TmemAllocation::V1);
998	
999	    // ignore first signal from softmax as no correction is required
1000	    pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
1001	    pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
1002	    ++pipeline_s0_c_consumer_state;
1003	
1004	    pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
1005	
1006	    // handle the last iteration differently (i.e. tmem_load/stsm for epi)
1007	    mask_tile_count -= 1;
1008	
1009	    CUTLASS_PRAGMA_NO_UNROLL
1010	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
1011	
1012	      pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
1013	
1014	      Tensor tTMEM_LOADVrS = make_tensor<ElementQK>(shape(tTMEM_LOADVcS));
1015	
1016	      // read row_wise new global max
1017	      copy(tiled_tmem_loadv, tTMEM_LOADVtS0, tTMEM_LOADVrS);
1018	
1019	      // e^(scale * (old_max - new_max)
1020	      float scale = ::exp2f(params.scale_softmax_log2 * (tTMEM_LOADVrS(kIdxOldRowMax) - tTMEM_LOADVrS(kIdxNewRowMax)));
1021	
1022	      pipeline_o.consumer_wait(pipeline_o_consumer_state);
1023	
1024	      correction_rescale(scale, uint32_t(TmemAllocation::O0));
1025	
1026	      pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1027	      ++pipeline_s1_c_consumer_state;
1028	
1029	      cutlass::arch::fence_view_async_tmem_store();
1030	
1031	      pipeline_o.consumer_release(pipeline_o_consumer_state);
1032	      ++pipeline_o_consumer_state;
1033	
1034	      pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
1035	
1036	      copy(tiled_tmem_loadv, tTMEM_LOADVtS1, tTMEM_LOADVrS);
1037	
1038	      scale = ::exp2f(params.scale_softmax_log2 * (tTMEM_LOADVrS(kIdxOldRowMax) - tTMEM_LOADVrS(kIdxNewRowMax)));
1039	
1040	      pipeline_o.consumer_wait(pipeline_o_consumer_state);
1041	
1042	      correction_rescale(scale, uint32_t(TmemAllocation::O1));
1043	
1044	      pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
1045	      ++pipeline_s0_c_consumer_state;
1046	
1047	      cutlass::arch::fence_view_async_tmem_store();
1048	
1049	      pipeline_o.consumer_release(pipeline_o_consumer_state);
1050	      ++pipeline_o_consumer_state;
1051	    }
1052	
1053	    pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1054	    ++pipeline_s1_c_consumer_state;
1055	
1056	    // do the final correction to O1
1057	    // better to somehow special-case it in the loop above
1058	    // doesn't matter for non-persistent code, but if it were
1059	    // persistent we do not want to release O too early
1060	
1061	    pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
1062	
1063	    // read from V0
1064	    // read row_sum and final row_max here
1065	    Tensor tTMEM_LOADVrS = make_tensor<ElementQK>(shape(tTMEM_LOADVcS));
1066	    copy(tiled_tmem_loadv, tTMEM_LOADVtS0, tTMEM_LOADVrS);
1067	
1068	    pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
1069	    ++pipeline_s0_c_consumer_state;
1070	
1071	    pipeline_o.consumer_wait(pipeline_o_consumer_state);
1072	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1073	    // store to epi smem
1074	
1075	    // loop:
1076	    //    TMEM_LOAD
1077	    //    FMUL2 scale = 1 / global_sum * out_quant_scale
1078	    //    F2FP
1079	    //    store to smem
1080	    Tensor sO = make_tensor(make_smem_ptr(shared_storage_epi.smem_o.data()), typename TensorStorageEpi::SmemLayoutO{});
1081	    Tensor gLSE = make_tensor(make_gmem_ptr(epilogue.params.ptr_LSE), select<0,3>(problem_shape), epilogue.params.dLSE);
1082	    correction_epilogue(params.scale_output / tTMEM_LOADVrS(kIdxFinalRowSum), _0{}, sO);
1083	
1084	    if (epilogue.params.ptr_LSE != nullptr) {
1085	      int row_idx = get<0>(tTMEM_LOADVcS(_0{})) + get<0>(TileShape{}) * get<0>(blk_coord);
1086	
1087	      int row_offset = 0;
1088	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1089	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1090	      }
1091	
1092	      ElementPV lse = cutlass::fast_log(tTMEM_LOADVrS(kIdxFinalRowSum)) + params.scale_softmax * tTMEM_LOADVrS(kIdxFinalRowMax);
1093	
1094	      if (row_idx < get<0>(problem_shape)) {
1095	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1096	      }
1097	    }
1098	
1099	    cutlass::arch::fence_view_async_tmem_load();
1100	
1101	    pipeline_o.consumer_release(pipeline_o_consumer_state);
1102	    ++pipeline_o_consumer_state;
1103	
1104	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1105	    ++pipeline_epi_producer_state;
1106	
1107	    pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
1108	
1109	    // load from V1
1110	    copy(tiled_tmem_loadv, tTMEM_LOADVtS1, tTMEM_LOADVrS);
1111	
1112	    pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1113	    ++pipeline_s1_c_consumer_state;
1114	
1115	    pipeline_o.consumer_wait(pipeline_o_consumer_state);
1116	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1117	
1118	    correction_epilogue(params.scale_output / tTMEM_LOADVrS(kIdxFinalRowSum), _1{}, sO);
1119	
1120	    if (epilogue.params.ptr_LSE != nullptr) {
1121	      int row_idx = get<0>(tTMEM_LOADVcS(_0{})) + get<0>(TileShape{}) * get<0>(blk_coord) + get<0>(TileShapeQK{});
1122	
1123	      ElementPV lse = cutlass::fast_log(tTMEM_LOADVrS(kIdxFinalRowSum)) + params.scale_softmax * tTMEM_LOADVrS(kIdxFinalRowMax);
1124	
1125	      int row_offset = 0;
1126	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1127	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1128	      }
1129	
1130	      if (row_idx < get<0>(problem_shape)) {
1131	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1132	      }
1133	    }
1134	
1135	    cutlass::arch::fence_view_async_tmem_load();
1136	
1137	    pipeline_o.consumer_release(pipeline_o_consumer_state);
1138	    ++pipeline_o_consumer_state;
1139	
1140	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1141	    ++pipeline_epi_producer_state;
1142	  }
1143	
1144	
1145	  template<
1146	    class BlkCoord, class ProblemShape, class ParamsProblemShape,
1147	    class TensorStorageEpi, class CollectiveEpilogue
1148	  >
1149	  CUTLASS_DEVICE auto
1150	  correction_empty(
1151	      BlkCoord const& blk_coord,
1152	      Params const& params, ProblemShape const& problem_shape,
1153	      ParamsProblemShape const& params_problem_shape,
1154	      TensorStorageEpi& shared_storage_epi,
1155	      PipelineE& pipeline_epi, typename PipelineE::PipelineState& pipeline_epi_producer_state,
1156	      CollectiveEpilogue& epilogue) {
1157	
1158	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1159	
1160	    Tensor sO = make_tensor(make_smem_ptr(shared_storage_epi.smem_o.data()), typename TensorStorageEpi::SmemLayoutO{});
1161	    Tensor gLSE = make_tensor(make_gmem_ptr(epilogue.params.ptr_LSE), select<0,3>(problem_shape), epilogue.params.dLSE);
1162	    float lse = -INFINITY;
1163	    int thread_idx = threadIdx.x % (4 * NumThreadsPerWarp);
1164	
1165	#if 1
1166	
1167	    using ElementOut = typename CollectiveEpilogue::ElementOut;
1168	    auto tiled_copy = make_cotiled_copy(
1169	        Copy_Atom<UniversalCopy<uint32_t>, ElementOut>{},
1170	        make_ordered_layout(make_shape(_128{}, Int<sizeof(uint32_t) / sizeof(ElementOut)>{}), Step<_1, _0>{}),
1171	        sO.layout());
1172	
1173	    auto thr_copy = tiled_copy.get_slice(thread_idx);
1174	    auto tOgO = thr_copy.partition_D(sO);
1175	    auto tOrO = make_tensor<ElementOut>(shape(tOgO(_,_,_,_0{})));
1176	    clear(tOrO);
1177	    
1178	    copy(tiled_copy, tOrO, tOgO(_,_,_,_0{}));
1179	#endif
1180	    
1181	    if (epilogue.params.ptr_LSE != nullptr) {
1182	      int row_idx = thread_idx + get<0>(TileShape{}) * get<0>(blk_coord);
1183	
1184	      int row_offset = 0;
1185	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1186	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1187	      }
1188	
1189	      if (row_idx < get<0>(problem_shape)) {
1190	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1191	      }
1192	    }
1193	
1194	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1195	    ++pipeline_epi_producer_state;
1196	
1197	    copy(tiled_copy, tOrO, tOgO(_,_,_,_1{}));
1198	    cutlass::arch::fence_view_async_shared();
1199	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1200	
1201	    if (epilogue.params.ptr_LSE != nullptr) {
1202	      int row_idx = thread_idx + get<0>(TileShape{}) * get<0>(blk_coord) + get<0>(TileShapeQK{});
1203	
1204	      int row_offset = 0;
1205	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1206	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1207	      }
1208	
1209	      if (row_idx < get<0>(problem_shape)) {
1210	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1211	      }
1212	    }
1213	
1214	    cutlass::arch::fence_view_async_shared();
1215	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
