210	
211	  template<class ProblemShape>
212	  static bool can_implement(ProblemShape const& problem_shape, Arguments const& args) {
213	    return true;
214	  }
215	
216	  template<class ProblemShape>
217	  static Params to_underlying_arguments(
218	      ProblemShape const& problem_shape,
219	      Arguments const& args,
220	      void* workspace) {
221	
222	    float scale_softmax = args.scale_softmax;
223	    if (scale_softmax == 0.0f) {
224	      scale_softmax = 1.0f / (float) std::sqrt(get<2>(problem_shape));
225	    }
226	    float log2_e = static_cast<float>(std::log2(std::exp(1.0)));
227	
228	    return Params{
229	        Load::to_underlying_arguments(problem_shape, args.load, workspace),
230	        args.scale_q * args.scale_k * scale_softmax,
231	        args.scale_q * args.scale_k * log2_e * scale_softmax,
232	        args.scale_v * args.inv_scale_o
233	    };
234	  }
