257	  template<class BlkCoord, class ProblemShape>
258	  CUTLASS_DEVICE auto
259	  mma(
260	      BlkCoord const& blk_coord,
261	      Params const& params, ProblemShape const& problem_shape,
262	      TensorStorage& storage,
263	      PipelineQ& pipeline_q, typename PipelineQ::PipelineState& pipeline_q_consumer_state,
264	      PipelineKV& pipeline_kv, typename PipelineKV::PipelineState& pipeline_kv_consumer_state,
265	      PipelineS& pipeline_s0, typename PipelineS::PipelineState& pipeline_s0_producer_state,
266	      PipelineS& pipeline_s1, typename PipelineS::PipelineState& pipeline_s1_producer_state,
267	      PipelineO& pipeline_corr, typename PipelineO::PipelineState& pipeline_corr_producer_state) {
268	
269	    auto pipeline_q_release_state = pipeline_q_consumer_state;
270	    auto pipeline_kv_release_state = pipeline_kv_consumer_state;
271	
272	    int mask_tile_count = Mask{}.get_trip_count(blk_coord, TileShape{}, problem_shape);
273	
274	    typename CollectiveMmaQK::TiledMma mma_qk;
275	    ThrMMA thr_mma_qk = mma_qk.get_slice(0);
276	
277	    typename CollectiveMmaPV::TiledMma mma_pv;
278	    TiledMMA mma_pv_ts = to_tiled_mma_sm100_ts(mma_pv);
279	    ThrMMA thr_mma_pv = mma_pv_ts.get_slice(0);
280	
281	    Tensor sQ = make_tensor(make_smem_ptr(storage.smem_q.data()), SmemLayoutQ{});
282	    Tensor sK = make_tensor(make_smem_ptr(storage.smem_k.data()), SmemLayoutK{});
283	    Tensor sV = make_tensor(make_smem_ptr(storage.smem_v.data()), SmemLayoutV{});
284	
285	    Tensor tSrQ = thr_mma_qk.make_fragment_A(sQ);
286	    Tensor tSrK = thr_mma_qk.make_fragment_B(sK);
287	    Tensor tOrV = thr_mma_pv.make_fragment_B(sV);
288	
289	    // tmem layout is
290	    // S0 S1`O0 O1
291	    // sequential in memory, where S overlaps with P and V
292	
293	    Tensor tStS = partition_fragment_C(mma_qk, select<0,1>(TileShapeQK{}));
294	    Tensor tOtO = partition_fragment_C(mma_pv_ts, select<0,1>(TileShapePV{}));
295	
296	    Tensor tStS0 = tStS;
297	    tStS0.data() = tStS.data().get() + uint32_t(TmemAllocation::S0);
298	    Tensor tStS1 = tStS;
299	    tStS1.data() = tStS.data().get() + uint32_t(TmemAllocation::S1);
300	
301	    Tensor tOtO0 = tOtO;
302	    tOtO0.data() = tOtO.data().get() + uint32_t(TmemAllocation::O0);
303	    Tensor tOtO1 = tOtO;
304	    tOtO1.data() = tOtO.data().get() + uint32_t(TmemAllocation::O1);
305	
306	    Tensor sP = make_tensor(make_smem_ptr((Element*)nullptr), typename CollectiveMmaPV::SmemLayoutA{});
307	    Tensor tOrP = thr_mma_pv.make_fragment_A(sP)(_, _, _, _0{});  // slice out staging
308	
309	    Tensor tOrP0 = tOrP;
310	    tOrP0.data() = tOrP0.data().get() + uint32_t(TmemAllocation::P0);
311	    Tensor tOrP1 = tOrP;
312	    tOrP1.data() = tOrP1.data().get() + uint32_t(TmemAllocation::P1);
313	
314	    int k_index = 0;
315	    int v_index = 0;
316	    int q_index = 0;
317	
318	    // wait for Q1
319	    q_index = pipeline_q_consumer_state.index();
320	    pipeline_q.consumer_wait(pipeline_q_consumer_state);
321	    ++pipeline_q_consumer_state;
322	
323	    Tensor tSrQ0 = tSrQ(_,_,_,q_index);
324	
325	
326	    // wait for K1
327	    k_index = pipeline_kv_consumer_state.index();
328	    pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
329	    ++pipeline_kv_consumer_state;
330	
331	    // gemm Q1 * K1 -> S1
332	    pipeline_s0.producer_acquire(pipeline_s0_producer_state);
333	
334	    gemm_zero_acc(mma_qk, tSrQ0, tSrK(_,_,_,k_index), tStS0);
335	
336	    pipeline_s0.producer_commit(pipeline_s0_producer_state);
337	    ++pipeline_s0_producer_state;
338	
339	    // release K1
340	    if constexpr (get<1>(ThreadShape{}) > 1) {
341	      pipeline_kv.consumer_release(pipeline_kv_release_state);
342	      ++pipeline_kv_release_state;
343	    }
344	
345	    // wait for Q2
346	    if constexpr (get<0>(ThreadShape{}) > 1 || get<2>(ThreadShape{}) > 1) {
347	      q_index = pipeline_q_consumer_state.index();
348	      pipeline_q.consumer_wait(pipeline_q_consumer_state);
349	      ++pipeline_q_consumer_state;
350	    }
351	
352	    Tensor tSrQ1 = tSrQ(_,_,_,q_index);
353	
354	    if constexpr (get<1>(ThreadShape{}) > 1) {
355	      k_index = pipeline_kv_consumer_state.index();
356	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
357	      ++pipeline_kv_consumer_state;
358	    }
359	
360	    pipeline_s1.producer_acquire(pipeline_s1_producer_state);
361	
362	    // gemm Q2 * K1 -> S2
363	    gemm_zero_acc(mma_qk, tSrQ1, tSrK(_,_,_,k_index), tStS1);
364	
365	    pipeline_s1.producer_commit(pipeline_s1_producer_state);
366	    ++pipeline_s1_producer_state;
367	
368	    // release K1
369	    pipeline_kv.consumer_release(pipeline_kv_release_state);
370	    ++pipeline_kv_release_state;
371	
372	    // wait for V1
373	    v_index = pipeline_kv_consumer_state.index();
374	    pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
375	    ++pipeline_kv_consumer_state;
376	
377	    // this acquire returns the ownership of all of S0 to the mma warp
378	    // including the P0 part
379	    // acquire corr first to take it out of the critical
380	    // path since softmax takes longer
381	    pipeline_corr.producer_acquire(pipeline_corr_producer_state);
382	    pipeline_s0.producer_acquire(pipeline_s0_producer_state);
383	
384	    // gemm P1 * V1 -> O1
385	    gemm_zero_acc(mma_pv_ts, tOrP0, tOrV(_,_,_,v_index), tOtO0);
386	
387	    pipeline_corr.producer_commit(pipeline_corr_producer_state);
388	    ++pipeline_corr_producer_state;
389	
390	      if constexpr (get<1>(ThreadShape{}) > 1) {
391	      pipeline_kv.consumer_release(pipeline_kv_release_state);
392	      ++pipeline_kv_release_state;
393	    }
394	
395	    mma_pv_ts.accumulate_ = UMMA::ScaleOut::Zero;
396	
397	    // loop:
398	    mask_tile_count -= 1;
399	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
400	
401	      // wait for Ki
402	      k_index = (pipeline_kv_consumer_state.index());
403	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
404	      ++pipeline_kv_consumer_state;
405	
406	      // gemm Q1 * Ki -> S1
407	      gemm_zero_acc(mma_qk, tSrQ0, tSrK(_,_,_,k_index), tStS0);
408	
409	      pipeline_s0.producer_commit(pipeline_s0_producer_state);
410	      ++pipeline_s0_producer_state;
411	
412	      if constexpr (get<1>(ThreadShape{}) > 1) {
413	        pipeline_kv.consumer_release(pipeline_kv_release_state);
414	        ++pipeline_kv_release_state;
415	      }
416	
417	      // gemm P2 * V(i-1) -> O2
418	      if constexpr (get<1>(ThreadShape{}) > 1) {
419	        v_index = pipeline_kv_consumer_state.index();
420	        pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
421	        ++pipeline_kv_consumer_state;
422	      }
423	
424	      pipeline_corr.producer_acquire(pipeline_corr_producer_state);
425	      pipeline_s1.producer_acquire(pipeline_s1_producer_state);
426	
427	      gemm_reset_zero_acc(mma_pv_ts, tOrP1, tOrV(_,_,_,v_index), tOtO1);
428	
429	      pipeline_corr.producer_commit(pipeline_corr_producer_state);
430	      ++pipeline_corr_producer_state;
431	
432	      // release V(i-1)
433	      pipeline_kv.consumer_release(pipeline_kv_release_state);
434	      ++pipeline_kv_release_state;
435	
436	      if constexpr (get<1>(ThreadShape{}) > 1) {
437	        k_index = (pipeline_kv_consumer_state.index());
438	        pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
439	        ++pipeline_kv_consumer_state;
440	      }
441	
442	      // gemm Q2 * Ki -> S2
443	      gemm_zero_acc(mma_qk, tSrQ1, tSrK(_,_,_,k_index), tStS1);
444	
445	      pipeline_s1.producer_commit(pipeline_s1_producer_state);
446	      ++pipeline_s1_producer_state;
447	
448	      // release Ki
449	      pipeline_kv.consumer_release(pipeline_kv_release_state);
450	      ++pipeline_kv_release_state;
451	
452	      // wait for Vi
453	      v_index = (pipeline_kv_consumer_state.index());
454	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
455	      ++pipeline_kv_consumer_state;
456	
457	      // gemm P1 * Vi -> O1
458	      pipeline_corr.producer_acquire(pipeline_corr_producer_state);
459	
460	      pipeline_s0.producer_acquire(pipeline_s0_producer_state);
461	
462	      gemm_reset_zero_acc(mma_pv_ts, tOrP0, tOrV(_,_,_,v_index), tOtO0);
463	
464	      pipeline_corr.producer_commit(pipeline_corr_producer_state);
465	      ++pipeline_corr_producer_state;
466	
467	      if constexpr (get<1>(ThreadShape{}) > 1) {
468	        pipeline_kv.consumer_release(pipeline_kv_release_state);
469	        ++pipeline_kv_release_state;
470	      }
471	    }
472	
473	    // release Q1
474	    pipeline_q.consumer_release(pipeline_q_release_state);
475	    ++pipeline_q_release_state;
476	
477	    // release Q2
478	    if constexpr (get<0>(ThreadShape{}) > 1) {
479	      pipeline_q.consumer_release(pipeline_q_release_state);
480	      ++pipeline_q_release_state;
481	    }
482	
483	    // wait for Vi
484	    if constexpr (get<1>(ThreadShape{}) > 1) {
485	      v_index = pipeline_kv_consumer_state.index();
486	      pipeline_kv.consumer_wait(pipeline_kv_consumer_state);
487	      ++pipeline_kv_consumer_state;
488	    }
489	
490	    // gemm P2 * Vi -> O2
491	    pipeline_corr.producer_acquire(pipeline_corr_producer_state);
492	    pipeline_s1.producer_acquire(pipeline_s1_producer_state);
493	
494	    gemm_reset_zero_acc(mma_pv_ts, tOrP1, tOrV(_,_,_,v_index), tOtO1);
495	
496	    pipeline_corr.producer_commit(pipeline_corr_producer_state);
497	    ++pipeline_corr_producer_state;
498	
499	    // release Vi
500	    pipeline_kv.consumer_release(pipeline_kv_release_state);
501	    ++pipeline_kv_release_state;
502	
503	    pipeline_s0.producer_commit(pipeline_s0_producer_state);
504	    ++pipeline_s0_producer_state;
505	
506	    pipeline_s1.producer_commit(pipeline_s1_producer_state);
507	    ++pipeline_s1_producer_state;
508	
509	    // T0 S00 B1, T0 S10 B1, T0 S00 B2, T0 S01 B1, T0 S10 B2, T0 S11 B1, T0 S01 B2, T1 S00 B1, T0 S11 B2, ...
510	    // Q1 * K1  , Q2 * K1  , S11 * V1 , Q1 * K2  , S21 * V1  , Q2 * K2 , S12 * V2 , Q1 * K3  , S22 * K2 , ...
511	  }
512	
513	  template<bool need_apply_mask, class Stage, class BlkCoord, class CoordTensor, class ProblemShape>
514	  CUTLASS_DEVICE auto
515	  softmax_step(
516	      float& row_max, float& row_sum,
517	      Stage stage, bool final_call,
518	      BlkCoord const& blk_coord, CoordTensor const& cS,
519	      Params const& params, ProblemShape const& problem_shape,
520	      PipelineS& pipeline_s, typename PipelineS::PipelineState& pipeline_s_consumer_state,
521	      PipelineC& pipeline_c, typename PipelineC::PipelineState& pipeline_c_producer_state,
522	      OrderBarrierSoftmax& order_s) {
523	
524	    Tensor tScS = typename CollectiveMmaQK::TiledMma{}.get_slice(0).partition_C(cS);
525	
526	    Tensor tStS = partition_fragment_C(typename CollectiveMmaQK::TiledMma{}, select<0,1>(TileShapeQK{}));
527	    tStS.data() = uint32_t(stage == _0{} ? TmemAllocation::S0 : TmemAllocation::S1);
528	
529	    Tensor tStS_v = tStS.compose(make_layout(make_shape(_128{}, _2{})));
530	    tStS_v.data() = uint32_t(stage == _0{} ? TmemAllocation::V0 : TmemAllocation::V1);
531	    Tensor tScS_v = tScS.compose(make_layout(make_shape(_128{}, _2{})));
532	
533	    auto tilePlikeFP32 = size<1>(TileShapeQK{}) / Int<sizeof(float)>{} * Int<sizeof(Element)>{};
534	    Tensor tStS_P = tStS.compose(make_layout(make_shape(_128{}, tilePlikeFP32)));
535	    tStS_P.data() = warp_uniform(uint32_t(stage == _0{} ? TmemAllocation::P0 : TmemAllocation::P1));
536	    Tensor tScS_P = tScS.compose(make_layout(make_shape(_128{}, tilePlikeFP32)));
537	
538	    // Each thread owns a single row
539	    using TMEM_LOAD = SM100_TMEM_LOAD_32dp32b32x; // 4x32 threads with 128 cols of 32b elem
540	    using TMEM_STORE = SM100_TMEM_STORE_32dp32b32x;  // 4x32 threads with 128 cols of 8b elem
541	    using TMEM_STORE_V = SM100_TMEM_STORE_32dp32b2x;   // 4x32 threads with 2 cols of 32b elem
542	
543	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
544	
545	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tStS);
546	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
547	
548	    Tensor tTMEM_LOADtS = thr_tmem_load.partition_S(tStS);
549	    Tensor tTMEM_LOADcS = thr_tmem_load.partition_D(tScS);
550	
551	    auto tiled_tmem_storev = make_tmem_copy(TMEM_STORE_V{}, tStS_v);
552	    auto thr_tmem_storev  = tiled_tmem_storev.get_slice(thread_idx);
553	
554	    Tensor tTMEM_STOREVtS = thr_tmem_storev.partition_D(tStS_v);
555	    Tensor tTMEM_STOREVcS = thr_tmem_storev.partition_S(tScS_v);
556	
557	    auto tiled_tmem_store = make_tmem_copy(TMEM_STORE{}, tStS_P);
558	    auto thr_tmem_store  = tiled_tmem_store.get_slice(thread_idx);
559	
560	    Tensor tTMEM_STOREtS_x4 = thr_tmem_store.partition_D(tStS_P);
561	    tTMEM_STOREtS_x4.data() = warp_uniform(tTMEM_STOREtS_x4.data().get());
562	    Tensor tTMEM_STOREcS = thr_tmem_store.partition_S(tScS_P);
563	
564	    // wait on tensor core pipe
565	    pipeline_s.consumer_wait(pipeline_s_consumer_state);
566	
567	    // read all of S from tmem into reg mem
568	    Tensor tTMEM_LOADrS = make_tensor<ElementQK>(shape(tTMEM_LOADcS));
569	    copy(tiled_tmem_load, tTMEM_LOADtS, tTMEM_LOADrS);
570	
571	    if constexpr (need_apply_mask) {
572	      Mask{}.apply_mask(tTMEM_LOADrS, tTMEM_LOADcS, problem_shape);
573	    }
574	
575	    ElementQK old_row_max = row_max;
576	    {
577	      // compute rowmax
578	      float row_max_0 = row_max;
579	      float row_max_1 = row_max;
580	      float row_max_2 = row_max;
581	      float row_max_3 = row_max;
582	      CUTLASS_PRAGMA_UNROLL
583	      for (int i = 0; i < size(tTMEM_LOADrS); i += 4) {
584	        row_max_0  = ::fmax(row_max_0, tTMEM_LOADrS(i));
585	        row_max_1 = ::fmax(row_max_1, tTMEM_LOADrS(i+1));
586	        row_max_2 = ::fmax(row_max_2, tTMEM_LOADrS(i+2));
587	        row_max_3 = ::fmax(row_max_3, tTMEM_LOADrS(i+3));
588	      }
589	      row_max = ::fmax(row_max_0, row_max_1);
590	      row_max = ::fmax(row_max, row_max_2);
591	      row_max = ::fmax(row_max, row_max_3);
592	    }
593	
594	    ElementQK row_max_safe = row_max == -INFINITY ? 0 : row_max;
595	
596	    Tensor tTMEM_STOREVrS = make_tensor<ElementQK>(shape(tTMEM_STOREVcS));
597	    tTMEM_STOREVrS(kIdxOldRowMax) = old_row_max;
598	    tTMEM_STOREVrS(kIdxNewRowMax) = row_max_safe;
599	    copy(tiled_tmem_storev, tTMEM_STOREVrS, tTMEM_STOREVtS);
600	
601	    pipeline_c.producer_commit(pipeline_c_producer_state);
602	    ++pipeline_c_producer_state;
603	
604	    // notify correction wg that they are ready (might need addtl ordering between S0 and S1 WG's)
605	
606	    ElementQK scale = params.scale_softmax_log2;
607	    ElementQK row_max_scale = row_max_safe * scale;
608	
609	    float2 scale_fp32x2 = make_float2(scale, scale);
610	    float2 minus_row_max_scale_fp32x2 = make_float2(-row_max_scale, -row_max_scale);
611	
612	    Tensor tTMEM_STORErS_x4 = make_tensor<uint32_t>(shape(tTMEM_STOREcS));
613	
614	    constexpr int kConversionsPerStep = 2;
615	
616	    Tensor tTMEM_STORErS_x4_e = recast<Array<Element, kConversionsPerStep>>(tTMEM_STORErS_x4);
617	
618	    NumericArrayConverter<Element, ElementQK, kConversionsPerStep> convert;
619	
620	    const int kReleasePipeCount = 10;  // must be multiple of 2
621	
622	    order_s.wait();
623	
624	    CUTLASS_PRAGMA_UNROLL
625	    for (int i = 0; i < size(tTMEM_LOADrS); i += 2) {
626	      float2 in = make_float2(
627	        tTMEM_LOADrS(i + 0),
628	        tTMEM_LOADrS(i + 1)
629	      );
630	      float2 out;
631	      cute::fma(out, scale_fp32x2, in, minus_row_max_scale_fp32x2);
632	      tTMEM_LOADrS(i + 0) = out.x;
633	      tTMEM_LOADrS(i + 1) = out.y;
634	
635	      tTMEM_LOADrS(i+0) = ::exp2f(tTMEM_LOADrS(i+0));
636	      tTMEM_LOADrS(i+1) = ::exp2f(tTMEM_LOADrS(i+1));
637	
638	      Array<ElementQK, kConversionsPerStep> in_conv;
639	      CUTLASS_PRAGMA_UNROLL
640	      for (int j = 0; j < kConversionsPerStep; j++) {
641	        in_conv[j] = tTMEM_LOADrS(i + j);
642	      }
643	      tTMEM_STORErS_x4_e[i / kConversionsPerStep] = convert(in_conv);
644	
645	
646	      if (i == size(tTMEM_LOADrS) - kReleasePipeCount) {
647	        order_s.arrive();
648	      }
649	
650	      // this prevents register spills in fp16
651	      if constexpr (size<2>(tTMEM_STORErS_x4) == _2{}) {
652	        if (i == size(tTMEM_LOADrS) - 6) {
653	          copy(tiled_tmem_store, tTMEM_STORErS_x4(_, _, 0), tTMEM_STOREtS_x4(_, _, 0));
654	        }
655	      }
656	    }
657	
658	    // tmem_store(reg_S8) -> op_P
659	    CUTE_STATIC_ASSERT_V(size<2>(tTMEM_STORErS_x4) <= _2{});
660	    CUTE_STATIC_ASSERT_V(size<1>(tTMEM_STORErS_x4) == _1{});
661	    copy(tiled_tmem_store, tTMEM_STORErS_x4(_, _, size<2>(tTMEM_STORErS_x4) - 1), tTMEM_STOREtS_x4(_, _, size<2>(tTMEM_STORErS_x4) - 1));
662	
663	    cutlass::arch::fence_view_async_tmem_store();
664	
665	    // notify tensor core warp that P is ready
666	    pipeline_s.consumer_release(pipeline_s_consumer_state);
667	    ++pipeline_s_consumer_state;
668	
669	    pipeline_c.producer_acquire(pipeline_c_producer_state);
670	
671	    ElementQK acc_scale = 0.5f * ::exp2f(scale * (old_row_max - row_max_safe));
672	    row_sum *= acc_scale;
673	    // row_sum = sum(reg_S)
674	    float2 local_row_sum_f32x2 = make_float2(row_sum, row_sum);
675	    float2 local_row_sum_1 = make_float2(0, 0);
676	    float2 local_row_sum_2 = make_float2(0, 0);
677	    float2 local_row_sum_3 = make_float2(0, 0);
678	
679	    CUTLASS_PRAGMA_UNROLL
680	    for (int i = 0; i < size(tTMEM_LOADrS); i += 8) {
681	      // row_sum += tTMEM_LOADrS(i);
682	      float2 in = make_float2(tTMEM_LOADrS(i), tTMEM_LOADrS(i+1));
683	      cute::add(local_row_sum_f32x2, local_row_sum_f32x2, in);
684	
685	      in = make_float2(tTMEM_LOADrS(i+2), tTMEM_LOADrS(i+2+1));
686	      cute::add(local_row_sum_1, local_row_sum_1, in);
687	
688	      in = make_float2(tTMEM_LOADrS(i+4), tTMEM_LOADrS(i+4+1));
689	      cute::add(local_row_sum_2, local_row_sum_2, in);
690	
691	      in = make_float2(tTMEM_LOADrS(i+6), tTMEM_LOADrS(i+6+1));
692	      cute::add(local_row_sum_3, local_row_sum_3, in);
693	    }
694	
695	    cute::add(local_row_sum_f32x2, local_row_sum_f32x2, local_row_sum_1);
696	    cute::add(local_row_sum_2, local_row_sum_2, local_row_sum_3);
697	    cute::add(local_row_sum_f32x2, local_row_sum_f32x2, local_row_sum_2);
698	    float local_row_sum = local_row_sum_f32x2.x + local_row_sum_f32x2.y;
699	
700	    row_sum = local_row_sum;
701	
702	    if (final_call) {
703	      // re-acquire the S part in the final step
704	      pipeline_s.consumer_wait(pipeline_s_consumer_state);
705	
706	      Tensor tTMEM_STOREVrS = make_tensor<ElementQK>(shape(tTMEM_STOREVcS));
707	      tTMEM_STOREVrS(kIdxFinalRowMax) = row_max;
708	      tTMEM_STOREVrS(kIdxFinalRowSum) = row_sum;
709	      copy(tiled_tmem_storev, tTMEM_STOREVrS, tTMEM_STOREVtS);
710	    }
711	  }
