713	  template<class Stage, class BlkCoord, class ProblemShape>
714	  CUTLASS_DEVICE auto
715	  softmax(
716	      Stage stage,
717	      BlkCoord const& blk_coord,
718	      Params const& params, ProblemShape const& problem_shape,
719	      PipelineS& pipeline_s, typename PipelineS::PipelineState& pipeline_s_consumer_state,
720	      PipelineC& pipeline_c, typename PipelineC::PipelineState& pipeline_c_producer_state,
721	      OrderBarrierSoftmax& order_s) {
722	
723	    int mask_tile_count = Mask{}.get_unmasked_trip_count(blk_coord, TileShape{}, problem_shape);
724	
725	    ElementQK row_max = -INFINITY;
726	    ElementQK row_sum = 0;
727	
728	    Tensor cS_base = make_identity_tensor(select<0,1>(TileShapeQK{}));
729	    auto logical_offset = make_coord(
730	        get<0>(blk_coord) * get<0>(TileShape{}) + (stage % get<0>(ThreadShape{})) * get<0>(TileShapeQK{}),
731	        0 + (stage % get<1>(ThreadShape{})) * get<1>(TileShapeQK{})
732	    );
733	    Tensor cS = domain_offset(logical_offset, cS_base);
734	
735	    pipeline_c.producer_acquire(pipeline_c_producer_state);
736	
737	    CUTLASS_PRAGMA_NO_UNROLL
738	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
739	      softmax_step<false /* need_apply_mask */>(
740	          row_max, row_sum, stage,
741	          (mask_tile_count == 1) &&
742	              (Mask{}.get_masked_trip_count(blk_coord, TileShape{}, problem_shape) == 0),
743	          blk_coord, cS, params, problem_shape,
744	          pipeline_s, pipeline_s_consumer_state,
745	          pipeline_c, pipeline_c_producer_state,
746	          order_s
747	      );
748	
749	      cS.data() = cS.data() + E<1>{} * get<1>(ThreadShape{}) * get<1>(TileShapeQK{});
750	    }
751	
752	    // Masked iterations
753	    mask_tile_count = Mask{}.get_masked_trip_count(blk_coord, TileShape{}, problem_shape);
754	
755	    CUTLASS_PRAGMA_NO_UNROLL
756	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
757	      softmax_step<true /* need_apply_mask */>(
758	          row_max, row_sum, stage, mask_tile_count == 1,
759	          blk_coord, cS, params, problem_shape,
760	          pipeline_s, pipeline_s_consumer_state,
761	          pipeline_c, pipeline_c_producer_state,
762	          order_s
763	      );
764	
765	      cS.data() = cS.data() + E<1>{} * get<1>(ThreadShape{}) * get<1>(TileShapeQK{});
766	    }
767	
768	    pipeline_c.producer_commit(pipeline_c_producer_state);
769	    ++pipeline_c_producer_state;
770	
771	    pipeline_c.producer_acquire(pipeline_c_producer_state);
772	    // empty step to sync against pipe s
773	    pipeline_s.consumer_release(pipeline_s_consumer_state);
774	    ++pipeline_s_consumer_state;
775	  }
