777	  template<class Stage, class TensorO>
778	  CUTLASS_DEVICE auto
779	  correction_epilogue(
780	      float scale,
781	      Stage stage,
782	      TensorO const& sO_01) {
783	
784	    using ElementOut = typename TensorO::value_type;
785	
786	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
787	
788	    Tensor sO = sO_01(_,_,stage);
789	
790	    // As opposed to the softmax, we do not have enough registers here
791	    // to load all of the values (for tile kv = 128), so we loop
792	    // good values would be either 32 or 64
793	    const int kCorrectionTileSize = 32 / sizeof(ElementOut);
794	
795	    using TMEM_LOAD = std::conditional_t<kCorrectionTileSize == 32, SM100_TMEM_LOAD_32dp32b32x, SM100_TMEM_LOAD_32dp32b16x>;  // 4x32 threads with 64 cols of 32b elem
796	
797	    typename CollectiveMmaPV::TiledMma mma;
798	    Tensor cO = make_identity_tensor(select<0,1>(TileShapePV{}));
799	    Tensor tOtO = partition_fragment_C(mma, select<0,1>(TileShapePV{}));
800	    Tensor tOcO = mma.get_slice(0).partition_C(cO);
801	    Tensor tOsO = mma.get_slice(0).partition_C(sO);
802	
803	    Tensor tOtO_i = logical_divide(tOtO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
804	    Tensor tOcO_i = logical_divide(tOcO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
805	    Tensor tOsO_i = logical_divide(tOsO, make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
806	
807	    if constexpr (decltype(stage == _0{})::value) {
808	      tOtO_i.data() = tOtO_i.data().get() + uint32_t(TmemAllocation::O0);
809	    }
810	    else {
811	      static_assert(decltype(stage == _1{})::value, "stage is either 0 or 1");
812	      tOtO_i.data() = tOtO_i.data().get() + uint32_t(TmemAllocation::O1);
813	    }
814	
815	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tOtO_i(make_coord(_, _), _0{}));
816	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
817	
818	    Tensor tTMEM_LOADtO = thr_tmem_load.partition_S(tOtO_i(make_coord(_, _), _));
819	    Tensor tTMEM_LOADcO = thr_tmem_load.partition_D(tOcO_i(make_coord(_, _), _));
820	    Tensor tTMEM_LOADsO = thr_tmem_load.partition_D(tOsO_i(make_coord(_, _), _));
821	
822	    float2 scale_f32x2 = make_float2(scale, scale);
823	
824	    // loop:
825	    //   TMEM_LOAD, FMUL2 scale, TMEM_STORE
826	    CUTLASS_PRAGMA_UNROLL
827	    for (int i = 0; i < get<2>(TileShape{}) / kCorrectionTileSize; i++) {
828	      Tensor tTMEM_LOADtO_i = tTMEM_LOADtO(_, _0{}, _0{}, i);
829	      Tensor tTMEM_LOADsO_i = tTMEM_LOADsO(_, _0{}, _0{}, i);
830	
831	      Tensor tTMrO = make_tensor<ElementPV>(shape(tTMEM_LOADcO(_, _0{}, _0{}, i)));
832	
833	      copy(tiled_tmem_load, tTMEM_LOADtO_i, tTMrO);
834	
835	#ifndef ONLY_SOFTMAX
836	      CUTLASS_PRAGMA_UNROLL
837	      for (int j = 0; j < size(tTMrO); j += 2) {
838	        float2 in = make_float2(tTMrO(j), tTMrO(j+1));
839	        float2 out;
840	        cute::mul(out, scale_f32x2, in);
841	        tTMrO(j) = out.x;
842	        tTMrO(j+1) = out.y;
843	      }
844	#endif
845	
846	      constexpr int N = 4 / sizeof(ElementOut);
847	      NumericArrayConverter<ElementOut, ElementPV, N> convert;
848	
849	      Tensor tSMrO = make_tensor_like<ElementOut>(tTMrO);
850	
851	      Tensor tCs = recast<decltype(convert)::source_type>(tTMrO);
852	      Tensor tCd = recast<decltype(convert)::result_type>(tSMrO);
853	
854	      CUTLASS_PRAGMA_UNROLL
855	      for (int j = 0; j < size(tCs); j++) {
856	        tCd(j) = convert.convert(tCs(j));
857	      }
858	
859	      Tensor tSMsO_i = recast<uint32_t>(tTMEM_LOADsO_i);
860	      Tensor tSMrO_i = recast<uint32_t>(tSMrO);
861	
862	      copy(AutoVectorizingCopyWithAssumedAlignment<128>{}, tSMrO_i, tSMsO_i);
863	    }
864	
865	    cutlass::arch::fence_view_async_shared();
866	  }
867	
868	  CUTLASS_DEVICE auto
869	  correction_rescale(
870	      float scale,
871	      uint32_t tmem_O) {
872	
873	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
874	
875	    // As opposed to the softmax, we do not have enough registers here
876	    // to load all of the values (for tile kv = 128), so we loop
877	    // good values would be either 32 or 64
878	    const int kCorrectionTileSize = 16;
879	
880	    using TMEM_LOAD = SM100_TMEM_LOAD_32dp32b16x;  // 4x32 threads with 64 cols of 32b elem
881	    using TMEM_STORE = SM100_TMEM_STORE_32dp32b16x;  // 4x32 threads with 64 cols of 32b elem
882	
883	    typename CollectiveMmaPV::TiledMma mma;
884	    Tensor cO = make_identity_tensor(select<0,1>(TileShapePV{}));
885	    Tensor tOtO = partition_fragment_C(mma, select<0,1>(TileShapePV{}));
886	    Tensor tOcO = mma.get_slice(0).partition_C(cO);
887	
888	    Tensor tOtO_i = tOtO.compose(make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
889	    Tensor tOcO_i = tOcO.compose(make_layout(make_shape(_128{}, Int<kCorrectionTileSize>{})));
890	
891	    tOtO_i.data() = tOtO_i.data().get() + tmem_O;
892	
893	    auto tiled_tmem_load = make_tmem_copy(TMEM_LOAD{}, tOtO_i);
894	    auto thr_tmem_load   = tiled_tmem_load.get_slice(thread_idx);
895	    auto tiled_tmem_store = make_tmem_copy(TMEM_STORE{}, tOtO_i);
896	    auto thr_tmem_store   = tiled_tmem_store.get_slice(thread_idx);
897	
898	    Tensor tTMEM_LOADtO = thr_tmem_load.partition_S(tOtO_i);
899	    Tensor tTMEM_LOADcO = thr_tmem_load.partition_D(tOcO_i);
900	    Tensor tTMEM_STOREtO = thr_tmem_store.partition_D(tOtO_i);
901	    Tensor tTMEM_STOREcO = thr_tmem_store.partition_S(tOcO_i);
902	    static_assert(shape(tTMEM_STOREcO) == shape(tTMEM_LOADcO));
903	
904	    float2 scale_f32x2 = make_float2(scale, scale);
905	
906	    Tensor tTMrO = make_tensor<ElementPV>(make_shape(shape(tTMEM_LOADcO), Int<128 / kCorrectionTileSize>{}));
907	
908	    auto copy_in = [&](int i) {
909	      Tensor tTMEM_LOADtO_i = tTMEM_LOADtO;
910	      tTMEM_LOADtO_i.data() = tTMEM_LOADtO_i.data().get() + uint32_t(i * kCorrectionTileSize);
911	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
912	      copy(tiled_tmem_load, tTMEM_LOADtO_i, tTMrO_i);
913	    };
914	
915	    auto copy_out = [&](int i) {
916	      Tensor tTMEM_STOREtO_i = tTMEM_STOREtO;
917	      tTMEM_STOREtO_i.data() = tTMEM_STOREtO_i.data().get() + uint32_t(i * kCorrectionTileSize);
918	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
919	      copy(tiled_tmem_store, tTMrO_i, tTMEM_STOREtO_i);
920	    };
921	
922	    // sequence: LLMSLMSLMSS
923	
924	    // loop:
925	    //   TMEM_LOAD, FMUL2 scale, TMEM_STORE
926	    copy_in(0);
927	
928	    int count = get<2>(TileShape{}) / kCorrectionTileSize;
929	
930	    CUTLASS_PRAGMA_UNROLL
931	    for (int i = 0; i < count; i++) {
932	      if (i != count - 1) {
933	        copy_in(i+1);
934	      }
935	
936	      Tensor tTMrO_i = tTMrO(_, i).compose(make_layout(shape<0>(tTMrO)));
937	      CUTLASS_PRAGMA_UNROLL
938	      for (int j = 0; j < size(tTMrO_i); j += 2) {
939	        float2 in = make_float2(tTMrO_i(j), tTMrO_i(j+1));
940	        float2 out;
941	        cute::mul(out, scale_f32x2, in);
942	        tTMrO_i(j) = out.x;
943	        tTMrO_i(j+1) = out.y;
944	      }
945	
946	      copy_out(i);
947	    }
948	  }
