950	  template<
951	    class BlkCoord, class ProblemShape, class ParamsProblemShape,
952	    class TensorStorageEpi, class CollectiveEpilogue
953	  >
954	  CUTLASS_DEVICE auto
955	  correction(
956	      BlkCoord const& blk_coord,
957	      Params const& params, ProblemShape const& problem_shape,
958	      ParamsProblemShape const& params_problem_shape,
959	      TensorStorageEpi& shared_storage_epi,
960	      PipelineC& pipeline_s0_c, typename PipelineC::PipelineState& pipeline_s0_c_consumer_state,
961	      PipelineC& pipeline_s1_c, typename PipelineC::PipelineState& pipeline_s1_c_consumer_state,
962	      PipelineO& pipeline_o, typename PipelineO::PipelineState& pipeline_o_consumer_state,
963	      PipelineE& pipeline_epi, typename PipelineE::PipelineState& pipeline_epi_producer_state,
964	      CollectiveEpilogue& epilogue) {
965	
966	    int mask_tile_count = Mask{}.get_trip_count(blk_coord, TileShape{}, problem_shape);
967	
968	    int thread_idx = threadIdx.x % (4 * cutlass::NumThreadsPerWarp);
969	
970	    Tensor tStS = partition_fragment_C(typename CollectiveMmaQK::TiledMma{}, select<0,1>(TileShapeQK{}));
971	
972	    Tensor cS = make_identity_tensor(select<0,1>(TileShapeQK{}));
973	    Tensor tScS = typename CollectiveMmaQK::TiledMma{}.get_slice(0).partition_C(cS);
974	
975	    Tensor tStS_v = tStS.compose(make_layout(make_shape(_128{}, _2{})));
976	    Tensor tScS_v = tScS.compose(make_layout(make_shape(_128{}, _2{})));
977	
978	    using TMEM_LOAD_V = SM100_TMEM_LOAD_32dp32b2x;   // 4x32 threads with 2 cols of 32b elem
979	
980	    auto tiled_tmem_loadv = make_tmem_copy(TMEM_LOAD_V{}, tStS_v);
981	    auto thr_tmem_loadv  = tiled_tmem_loadv.get_slice(thread_idx);
982	
983	    Tensor tTMEM_LOADVtS = thr_tmem_loadv.partition_S(tStS_v);
984	    Tensor tTMEM_LOADVcS = thr_tmem_loadv.partition_D(tScS_v);
985	
986	    Tensor tTMEM_LOADVtS0 = tTMEM_LOADVtS;
987	    tTMEM_LOADVtS0.data() = tTMEM_LOADVtS0.data().get() + uint32_t(TmemAllocation::V0);
988	    Tensor tTMEM_LOADVtS1 = tTMEM_LOADVtS;
989	    tTMEM_LOADVtS1.data() = tTMEM_LOADVtS1.data().get() + uint32_t(TmemAllocation::V1);
990	
991	    // ignore first signal from softmax as no correction is required
992	    pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
993	    pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
994	    ++pipeline_s0_c_consumer_state;
995	
996	    pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
997	
998	    // handle the last iteration differently (i.e. tmem_load/stsm for epi)
999	    mask_tile_count -= 1;
1000	
1001	    CUTLASS_PRAGMA_NO_UNROLL
1002	    for (; mask_tile_count > 0; mask_tile_count -= 1) {
1003	
1004	      pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
1005	
1006	      Tensor tTMEM_LOADVrS = make_tensor<ElementQK>(shape(tTMEM_LOADVcS));
1007	
1008	      // read row_wise new global max
1009	      copy(tiled_tmem_loadv, tTMEM_LOADVtS0, tTMEM_LOADVrS);
1010	
1011	      // e^(scale * (old_max - new_max)
1012	      float scale = ::exp2f(params.scale_softmax_log2 * (tTMEM_LOADVrS(kIdxOldRowMax) - tTMEM_LOADVrS(kIdxNewRowMax)));
1013	
1014	      pipeline_o.consumer_wait(pipeline_o_consumer_state);
1015	
1016	      correction_rescale(scale, uint32_t(TmemAllocation::O0));
1017	
1018	      pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1019	      ++pipeline_s1_c_consumer_state;
1020	
1021	      cutlass::arch::fence_view_async_tmem_store();
1022	
1023	      pipeline_o.consumer_release(pipeline_o_consumer_state);
1024	      ++pipeline_o_consumer_state;
1025	
1026	      pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
1027	
1028	      copy(tiled_tmem_loadv, tTMEM_LOADVtS1, tTMEM_LOADVrS);
1029	
1030	      scale = ::exp2f(params.scale_softmax_log2 * (tTMEM_LOADVrS(kIdxOldRowMax) - tTMEM_LOADVrS(kIdxNewRowMax)));
1031	
1032	      pipeline_o.consumer_wait(pipeline_o_consumer_state);
1033	
1034	      correction_rescale(scale, uint32_t(TmemAllocation::O1));
1035	
1036	      pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
1037	      ++pipeline_s0_c_consumer_state;
1038	
1039	      cutlass::arch::fence_view_async_tmem_store();
1040	
1041	      pipeline_o.consumer_release(pipeline_o_consumer_state);
1042	      ++pipeline_o_consumer_state;
1043	    }
1044	
1045	    pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1046	    ++pipeline_s1_c_consumer_state;
1047	
1048	    // do the final correction to O1
1049	    // better to somehow special-case it in the loop above
1050	    // doesn't matter for non-persistent code, but if it were
1051	    // persistent we do not want to release O too early
1052	
1053	    pipeline_s0_c.consumer_wait(pipeline_s0_c_consumer_state);
1054	
1055	    // read from V0
1056	    // read row_sum and final row_max here
1057	    Tensor tTMEM_LOADVrS = make_tensor<ElementQK>(shape(tTMEM_LOADVcS));
1058	    copy(tiled_tmem_loadv, tTMEM_LOADVtS0, tTMEM_LOADVrS);
1059	
1060	    pipeline_s0_c.consumer_release(pipeline_s0_c_consumer_state);
1061	    ++pipeline_s0_c_consumer_state;
1062	
1063	    pipeline_o.consumer_wait(pipeline_o_consumer_state);
1064	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1065	    // store to epi smem
1066	
1067	    // loop:
1068	    //    TMEM_LOAD
1069	    //    FMUL2 scale = 1 / global_sum * out_quant_scale
1070	    //    F2FP
1071	    //    store to smem
1072	    Tensor sO = make_tensor(make_smem_ptr(shared_storage_epi.smem_o.data()), typename TensorStorageEpi::SmemLayoutO{});
1073	    Tensor gLSE = make_tensor(make_gmem_ptr(epilogue.params.ptr_LSE), select<0,3>(problem_shape), epilogue.params.dLSE);
1074	    
1075	    correction_epilogue(params.scale_output / tTMEM_LOADVrS(kIdxFinalRowSum), _0{}, sO);
1076	
1077	    if (epilogue.params.ptr_LSE != nullptr) {
1078	      int row_idx = get<0>(tTMEM_LOADVcS(_0{})) + get<0>(TileShape{}) * get<0>(blk_coord);
1079	
1080	      int row_offset = 0;
1081	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1082	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1083	      }
1084	
1085	      ElementPV lse = cutlass::fast_log(tTMEM_LOADVrS(kIdxFinalRowSum)) + params.scale_softmax * tTMEM_LOADVrS(kIdxFinalRowMax);
1086	
1087	      if (row_idx < get<0>(problem_shape)) {
1088	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1089	      }
1090	    }
1091	
1092	    cutlass::arch::fence_view_async_tmem_load();
1093	
1094	    pipeline_o.consumer_release(pipeline_o_consumer_state);
1095	    ++pipeline_o_consumer_state;
1096	
1097	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1098	    ++pipeline_epi_producer_state;
1099	
1100	    pipeline_s1_c.consumer_wait(pipeline_s1_c_consumer_state);
1101	
1102	    // load from V1
1103	    copy(tiled_tmem_loadv, tTMEM_LOADVtS1, tTMEM_LOADVrS);
1104	
1105	    pipeline_s1_c.consumer_release(pipeline_s1_c_consumer_state);
1106	    ++pipeline_s1_c_consumer_state;
1107	
1108	    pipeline_o.consumer_wait(pipeline_o_consumer_state);
1109	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1110	
1111	    correction_epilogue(params.scale_output / tTMEM_LOADVrS(kIdxFinalRowSum), _1{}, sO);
1112	
1113	    if (epilogue.params.ptr_LSE != nullptr) {
1114	      int row_idx = get<0>(tTMEM_LOADVcS(_0{})) + get<0>(TileShape{}) * get<0>(blk_coord) + get<0>(TileShapeQK{});
1115	
1116	      ElementPV lse = cutlass::fast_log(tTMEM_LOADVrS(kIdxFinalRowSum)) + params.scale_softmax * tTMEM_LOADVrS(kIdxFinalRowMax);
1117	
1118	      int row_offset = 0;
1119	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1120	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1121	      }
1122	
1123	      if (row_idx < get<0>(problem_shape)) {
1124	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1125	      }
1126	    }
1127	
1128	    cutlass::arch::fence_view_async_tmem_load();
1129	
1130	    pipeline_o.consumer_release(pipeline_o_consumer_state);
1131	    ++pipeline_o_consumer_state;
1132	
1133	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1134	    ++pipeline_epi_producer_state;
1135	  }
1136	
1137	
1138	  template<
1139	    class BlkCoord, class ProblemShape, class ParamsProblemShape,
1140	    class TensorStorageEpi, class CollectiveEpilogue
1141	  >
1142	  CUTLASS_DEVICE auto
1143	  correction_empty(
1144	      BlkCoord const& blk_coord,
1145	      Params const& params, ProblemShape const& problem_shape,
1146	      ParamsProblemShape const& params_problem_shape,
1147	      TensorStorageEpi& shared_storage_epi,
1148	      PipelineE& pipeline_epi, typename PipelineE::PipelineState& pipeline_epi_producer_state,
1149	      CollectiveEpilogue& epilogue) {
1150	
1151	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1152	
1153	    Tensor sO = make_tensor(make_smem_ptr(shared_storage_epi.smem_o.data()), typename TensorStorageEpi::SmemLayoutO{});
1154	    Tensor gLSE = make_tensor(make_gmem_ptr(epilogue.params.ptr_LSE), select<0,3>(problem_shape), epilogue.params.dLSE);
1155	    float lse = -INFINITY;
1156	    int thread_idx = threadIdx.x % (4 * NumThreadsPerWarp);
1157	
1158	#if 1
1159	
1160	    using ElementOut = typename CollectiveEpilogue::ElementOut;
1161	    auto tiled_copy = make_cotiled_copy(
1162	        Copy_Atom<UniversalCopy<uint32_t>, ElementOut>{},
1163	        make_ordered_layout(make_shape(_128{}, Int<sizeof(uint32_t) / sizeof(ElementOut)>{}), Step<_1, _0>{}),
1164	        sO.layout());
1165	
1166	    auto thr_copy = tiled_copy.get_slice(thread_idx);
1167	    auto tOgO = thr_copy.partition_D(sO);
1168	    auto tOrO = make_tensor<ElementOut>(shape(tOgO(_,_,_,_0{})));
1169	    clear(tOrO);
1170	    
1171	    copy(tiled_copy, tOrO, tOgO(_,_,_,_0{}));
1172	#endif
1173	    
1174	    if (epilogue.params.ptr_LSE != nullptr) {
1175	      int row_idx = thread_idx + get<0>(TileShape{}) * get<0>(blk_coord);
1176	
1177	      int row_offset = 0;
1178	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1179	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1180	      }
1181	
1182	      if (row_idx < get<0>(problem_shape)) {
1183	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1184	      }
1185	    }
1186	
1187	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1188	    ++pipeline_epi_producer_state;
1189	
1190	    copy(tiled_copy, tOrO, tOgO(_,_,_,_1{}));
1191	    cutlass::arch::fence_view_async_shared();
1192	    pipeline_epi.producer_acquire(pipeline_epi_producer_state);
1193	
1194	    if (epilogue.params.ptr_LSE != nullptr) {
1195	      int row_idx = thread_idx + get<0>(TileShape{}) * get<0>(blk_coord) + get<0>(TileShapeQK{});
1196	
1197	      int row_offset = 0;
1198	      if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
1199	        row_offset = get<0>(params_problem_shape).cumulative_length[get<2,1>(blk_coord)];
1200	      }
1201	
1202	      if (row_idx < get<0>(problem_shape)) {
1203	        gLSE(row_idx + row_offset, get<2>(blk_coord)) = lse;
1204	      }
1205	    }
1206	
1207	    cutlass::arch::fence_view_async_shared();
1208	    pipeline_epi.producer_commit(pipeline_epi_producer_state);
1209	    ++pipeline_epi_producer_state;
1210	  }
1211	
1212	};
