41	  class Element,
42	  class ElementAcc,
43	  class TileShape,  // Q, D, _
44	  class StrideO,    // Q, D, B
45	  class StrideLSE_,   // Q, B
46	  class OrderLoadEpilogue = cute::false_type
47	>
48	struct Sm100FmhaFwdEpilogueTmaWarpspecialized {
49	    
50	  using Pipeline = cutlass::PipelineAsync<2>;
51	
52	//  using SmemLayoutO = decltypa(make_layout(append<3>(select<0,1>(TileShape_WG{}), _2{})));
53	  using SmemLayoutAtomO = decltype(cutlass::gemm::collective::detail::sm100_smem_selector<
54	        cute::UMMA::Major::K, Element, tuple_element_t<0, TileShape>, tuple_element_t<1, TileShape>>());
55	//  using SmemLayoutAtomO = decltype(make_ordered_layout(select<0,1>(TileShape{}), Step<_1, _0>{}));
56	  using SmemLayoutO = decltype(tile_to_shape(SmemLayoutAtomO{}, replace<2>(TileShape{}, _2{}), Step<_2, _1, _3>{}));
57	  using SmemLayoutO_ = SmemLayoutO;
58	  using StrideLSE = StrideLSE_;
59	  using ElementOut = Element;
60	
61	  static const int NumWarpsEpilogue = 1;
62	  static const int NumWarpsLoad = 1;
63	
64	  struct TensorStorage {
65	
66	    using SmemLayoutO = SmemLayoutO_;
67	    cute::array_aligned<Element, cute::cosize_v<SmemLayoutO>> smem_o;
68	
69	  };
70	
71	  struct Arguments {
72	    Element* ptr_O;
73	    StrideO dO;
74	
75	    ElementAcc* ptr_LSE;
76	    StrideLSE dLSE;
77	  };
78	
79	  using TMA_O = decltype(make_tma_copy(
80	    SM90_TMA_STORE{},
81	    make_tensor((Element*) nullptr, repeat_like(StrideO{}, 0), StrideO{}),
82	    SmemLayoutO{}(_,_,_0{})
83	  ));
84	
85	
86	  struct Params {
87	    TMA_O tma_store_o;
88	
89	    ElementAcc* ptr_LSE;
90	    StrideLSE dLSE;
91	  };
92	
93	  // FMHA and MLA have different input ProblemShapes; 
94	  // get problem_shape_O according to the input ProblemShape.
95	  template<class ProblemShape>
96	  CUTLASS_DEVICE static constexpr
97	  auto get_problem_shape_O (
98	    ProblemShape const& problem_shape) {
99	    if constexpr (rank_v<decltype(get<2>(ProblemShape{}))> == 2) {
100	      return replace<1>(select<0,2,3>(problem_shape), get<2, 0>(problem_shape));
101	    } else {
102	      return select<0,2,3>(problem_shape);
103	    }
104	  }
105	
106	  template<class ProblemShape>
107	  static Params to_underlying_arguments(
108	      ProblemShape const& problem_shape,
109	      Arguments const& args,
110	      void* workspace = nullptr) {
111	
112	    auto ptr_O = args.ptr_O;
113	    StrideO dO = args.dO;
114	
115	    auto problem_shape_O = get_problem_shape_O(problem_shape);
116	
117	    if constexpr (is_variable_length_v<tuple_element_t<0, ProblemShape>>) {
118	      auto cumulative_length_q = get<0>(problem_shape).cumulative_length;
119	      if (cumulative_length_q != nullptr) {
120	          int max_length_q = get<0>(problem_shape).max_length;
121	          get<0>(problem_shape_O).max_length = max(1, max_length_q);
122	          // for variable sequence lenght, the batch is in units of row_stride
123	          get<2,1>(dO) = get<0>(dO);
124	          get<2,1>(problem_shape_O) = max(1, max_length_q * (1 + get<2,1>(problem_shape_O)));
125	          // offset ptr by the amount we add back in later
126	          ptr_O -= max_length_q * get<0>(dO);
127	      }
128	    } else {
129	      get<0>(problem_shape_O) = max(1, get<0>(problem_shape_O));
130	    }
131	
132	    auto tma_store_o = make_tma_copy(
133	      SM90_TMA_STORE{},
134	      make_tensor(ptr_O, problem_shape_O, dO),
135	      SmemLayoutO{}(_,_,_0{})
136	    );
137	
138	    return {
139	      tma_store_o,
140	      args.ptr_LSE,
141	      args.dLSE
142	    };
143	  }
144	
145	  CUTLASS_DEVICE
146	  static void prefetch_tma_descriptors(Params const& params) {
147	    cute::prefetch_tma_descriptor(params.tma_store_o.get_tma_descriptor());
148	  }
149	
150	  const Params& params;
151	
152	  CUTLASS_DEVICE Sm100FmhaFwdEpilogueTmaWarpspecialized(const Params& params) : params(params) {}
153	
154	  template<class BlkCoord, class ProblemShape, class ParamsProblemShape>
155	  CUTLASS_DEVICE auto
156	  store(
157	      BlkCoord const& blk_coord_in, ProblemShape const& problem_shape,
158	      Params const& params, ParamsProblemShape const& params_problem_shape,
159	      TensorStorage& shared_storage,
160	      Pipeline& pipeline, typename Pipeline::PipelineState& pipeline_consumer_state) {
161	
162	    BlkCoord blk_coord = blk_coord_in;
163	    uint32_t lane_predicate = cute::elect_one_sync();
164	
165	    using X = Underscore;
166	
167	    int o0_index = 2 * get<0>(blk_coord);
168	    int o1_index = 2 * get<0>(blk_coord) + 1;
169	
170	    Tensor mO_qdl_p = params.tma_store_o.get_tma_tensor(get_problem_shape_O(problem_shape));
171	    // offset mode 0 by (max_length - real_length)
172	    // offset mode 3,1 by cumulative_length + real_length
173	    // the ptr is already offset by - max_length
174	    // so in total this achieves 
175	    int offs_0 = 0;
176	    int offs_2_1 = 0;
177	
178	    if constexpr (is_variable_length_v<tuple_element_t<0, ParamsProblemShape>>) {
179	      auto cumulative_length_q = get<0>(params_problem_shape).cumulative_length;
180	      if (cumulative_length_q != nullptr) {
181	        int max_length_q = get<0>(params_problem_shape).max_length;
182	        offs_0 = max_length_q - get<0>(problem_shape);
183	        offs_2_1 = cumulative_length_q[get<2,1>(blk_coord)] + get<0>(problem_shape);
184	        get<2,1>(blk_coord) = 0;
185	      }
186	    }
187	
188	    Tensor mO_qdl = domain_offset(make_coord(offs_0, _0{}, make_coord(_0{}, offs_2_1)), mO_qdl_p);
189	
190	    Tensor gO_qdl = local_tile(mO_qdl, TileShape{}, make_coord(_, _, _), Step<_1, _1, X>{});
191	    Tensor gO = gO_qdl(_, _, _, _0{}, get<2>(blk_coord));
192	    Tensor sO = make_tensor(make_smem_ptr(shared_storage.smem_o.data()), SmemLayoutO{});
193	    auto block_tma = params.tma_store_o.get_slice(0);
194	    Tensor tOsO = block_tma.partition_S(sO);
195	    Tensor tOgO = block_tma.partition_D(gO);
196	
197	    auto pipeline_release_state = pipeline_consumer_state;
198	
199	    // O1 O2
200	    // one pipeline: O
201	    // wait from corr, issue tma store on smem
202	    pipeline.consumer_wait(pipeline_consumer_state);
203	    ++pipeline_consumer_state;
204	
205	    if (lane_predicate) {
206	      copy(params.tma_store_o, tOsO(_,_,_,_0{}), tOgO(_,_,_,o0_index));
207	    }
208	    tma_store_arrive();
209	
210	    pipeline.consumer_wait(pipeline_consumer_state);
211	    ++pipeline_consumer_state;
212	
213	    if (lane_predicate) {
214	      copy(params.tma_store_o, tOsO(_,_,_,_1{}), tOgO(_,_,_,o1_index));
215	    }
216	    tma_store_arrive();
217	
218	    tma_store_wait<1>();
219	
220	    pipeline.consumer_release(pipeline_release_state);
221	    ++pipeline_release_state;
222	
223	    tma_store_wait<0>();
224	
225	    if constexpr (cute::is_same_v<OrderLoadEpilogue, cute::true_type>) {
226	      cutlass::arch::NamedBarrier::arrive((NumWarpsLoad + NumWarpsEpilogue) * NumThreadsPerWarp, 
227	                                          cutlass::arch::ReservedNamedBarriers::EpilogueBarrier);
228	    }
229	
230	    pipeline.consumer_release(pipeline_release_state);
231	    ++pipeline_release_state;
232	
233	  } 
234	
235	};
236	
237	}  // namespace cutlass::fmha::collective
