44	template <
45	  int Stages_,
46	  class ClusterShape = Shape<int,int,_1>,
47	  class AtomThrShape_MNK_ = Shape<_1,_1,_1>
48	>
49	class PipelineTmaAsyncMla {
50	
51	public:
52	  static constexpr uint32_t Stages = Stages_;
53	  using AtomThrShape_MNK = AtomThrShape_MNK_;
54	
55	private:
56	  using Impl = PipelineTmaUmmaAsync<Stages_, ClusterShape, AtomThrShape_MNK_>;
57	
58	public:
59	  using FullBarrier  = typename Impl::FullBarrier;
60	  using EmptyBarrier = typename Impl::EmptyBarrier;
61	  using ProducerBarrierType = typename Impl::ProducerBarrierType;
62	  using ConsumerBarrierType = typename Impl::ConsumerBarrierType;
63	  using PipelineState = typename Impl::PipelineState;
64	  using SharedStorage = typename Impl::SharedStorage;
65	  using ThreadCategory = typename Impl::ThreadCategory;
66	  using Params = typename Impl::Params;
67	
68	
69	  using McastDirection = McastDirection;
70	
71	  // Helper function to initialize barriers
72	  static
73	  CUTLASS_DEVICE
74	  void
75	  init_barriers(SharedStorage& storage, Params params, ClusterShape cluster_shape) {
76	    int warp_idx = canonical_warp_idx_sync();
77	    if (warp_idx == params.initializing_warp) {
78	      // Barrier FULL and EMPTY init
79	      constexpr int producer_arv_cnt = 1;
80	      auto atom_thr_shape = AtomThrShape_MNK{};
81	      uint32_t const multicast_consumer_arrival_count = (cute::size<0>(cluster_shape) / cute::size<0>(atom_thr_shape)) +
82	                                     (cute::size<1>(cluster_shape) / cute::size<1>(atom_thr_shape)) - 1;
83	
84	      cutlass::arch::detail::initialize_barrier_array_pair_aligned<decltype(storage.full_barrier_), decltype(storage.empty_barrier_), Stages>(
85	          storage.full_barrier_, storage.empty_barrier_, producer_arv_cnt, multicast_consumer_arrival_count);
86	    }
87	    cutlass::arch::fence_barrier_init();
88	  }
89	
90	  static
91	  CUTLASS_DEVICE
92	  void
93	  init_barriers(SharedStorage& storage, Params params, ClusterShape cluster_shape, McastDirection mcast_direction) {
94	    auto atom_thr_shape = AtomThrShape_MNK{};
95	
96	    int warp_idx = canonical_warp_idx_sync();
97	    if (warp_idx == params.initializing_warp) {
98	      // Barrier FULL and EMPTY init
99	      constexpr int producer_arv_cnt = 1;
100	      uint32_t const multicast_consumer_arrival_count = (mcast_direction == McastDirection::kRow) ?
101	        cute::size<1>(cluster_shape) / cute::size<1>(atom_thr_shape) : // Mcast with row ctas
102	        cute::size<0>(cluster_shape) / cute::size<0>(atom_thr_shape);  // Mcast with col ctas
103	
104	      cutlass::arch::detail::initialize_barrier_array_pair_aligned<decltype(storage.full_barrier_), decltype(storage.empty_barrier_), Stages>(
105	          storage.full_barrier_, storage.empty_barrier_, producer_arv_cnt, multicast_consumer_arrival_count);
106	    }
107	    cutlass::arch::fence_barrier_init();
108	  }
109	
110	  CUTLASS_DEVICE
111	  void init_masks(ClusterShape cluster_shape, dim3 block_id_in_cluster = cute::block_id_in_cluster()) {
112	    // Calculate consumer mask
113	    if (params_.role == ThreadCategory::Consumer) {
114	      auto cluster_layout = make_layout(cluster_shape);
115	      block_id_mask_ = detail::calculate_multicast_mask<McastDirection::kRowCol>(cluster_shape, AtomThrShape_MNK{}, block_id_in_cluster);
116	    }
117	  }
118	
119	  CUTLASS_DEVICE
120	  void init_masks(ClusterShape cluster_shape, McastDirection mcast_direction) {
121	    // Calculate consumer mask
122	    dim3 block_id_in_cluster = cute::block_id_in_cluster();
123	    auto cluster_layout = make_layout(cluster_shape);
124	    if (mcast_direction == McastDirection::kRow) {
125	      block_id_mask_ = detail::calculate_multicast_mask<McastDirection::kRow>(cluster_shape, AtomThrShape_MNK{}, block_id_in_cluster);
126	    }
127	    else {
128	      block_id_mask_ = detail::calculate_multicast_mask<McastDirection::kCol>(cluster_shape, AtomThrShape_MNK{}, block_id_in_cluster);
129	    }
130	  }
131	
132	
133	public:
134	  template<typename InitBarriers = cute::true_type, typename InitMasks = cute::true_type>
135	  CUTLASS_DEVICE
136	  PipelineTmaAsyncMla(SharedStorage& storage, Params params, ClusterShape cluster_shape, InitBarriers = {}, InitMasks = {})
137	      : impl_(storage, params, cluster_shape, cute::false_type{}, cute::false_type{})
138	      , params_(params)
139	      , empty_barrier_ptr_(&storage.empty_barrier_[0])
140	      , full_barrier_ptr_(&storage.full_barrier_[0]) {
141	        static_assert(cute::is_same_v<InitBarriers, cute::true_type> || cute::is_same_v<InitBarriers, cute::false_type>);
142	        if constexpr (cute::is_same_v<InitBarriers, cute::true_type>) {
143	          init_barriers(storage, params_, cluster_shape);
144	        }
145	
146	        static_assert(cute::is_same_v<InitMasks, cute::true_type> || cute::is_same_v<InitMasks, cute::false_type>);
147	        if constexpr (cute::is_same_v<InitMasks, cute::true_type>) {
148	          init_masks(cluster_shape);
149	        }
150	  }
151	
152	  template<typename InitBarriers = cute::true_type, typename InitMasks = cute::true_type>
153	  CUTLASS_DEVICE
154	  PipelineTmaAsyncMla(SharedStorage& storage, Params params, ClusterShape cluster_shape, McastDirection mcast_direction, InitBarriers = {}, InitMasks = {})
155	      : impl_(storage, params, cluster_shape, cute::false_type{}, cute::false_type{})
156	      , params_(params)
157	      , empty_barrier_ptr_(&storage.empty_barrier_[0])
158	      , full_barrier_ptr_(&storage.full_barrier_[0]) {
159	    static_assert(cute::is_same_v<InitBarriers, cute::true_type> || cute::is_same_v<InitBarriers, cute::false_type>);
160	    if constexpr (cute::is_same_v<InitBarriers, cute::true_type>) {
161	      init_barriers(storage, params_, cluster_shape, mcast_direction);
162	    }
163	
164	    static_assert(cute::is_same_v<InitMasks, cute::true_type> || cute::is_same_v<InitMasks, cute::false_type>);
165	    if constexpr (cute::is_same_v<InitMasks, cute::true_type>) {
166	      init_masks(cluster_shape, mcast_direction);
167	    }
168	  }
169	
170	
171	  CUTLASS_DEVICE
172	  void producer_acquire(PipelineState state, ProducerToken barrier_token = {BarrierStatus::WaitAgain}) {
173	    impl_.producer_acquire(state, barrier_token);
174	  }
175	
176	  CUTLASS_DEVICE
177	  void producer_acquire_bytes(uint32_t stage, uint32_t bytes, uint32_t phase, ProducerToken barrier_token) {
178	    detail::pipeline_check_is_producer(params_.role);
179	    if (barrier_token != BarrierStatus::WaitDone) {
180	      empty_barrier_ptr_[stage].wait(phase);
181	    }
182	
183	    if (params_.is_leader) {
184	      full_barrier_ptr_[stage].arrive_and_expect_tx(bytes);
185	    }
186	    #ifndef NDEBUG
187	    if (params_.role == ThreadCategory::Consumer || params_.role == ThreadCategory::NonParticipant) {
188	      asm volatile ("brkpt;\n" ::);
189	    }
190	
191	    // Most likely you have elected more than one leader
192	    if (params_.is_leader && (threadIdx.x % 32 != 0)) {
193	      asm volatile ("brkpt;\n" ::);
194	    }
195	    #endif
196	  }
197	
198	  CUTLASS_DEVICE
199	  void producer_acquire_bytes(PipelineState state, uint32_t bytes, ProducerToken barrier_token = {BarrierStatus::WaitAgain}) {
200	    producer_acquire_bytes(state.index(), bytes, state.phase(), barrier_token);
201	  }
202	
203	  CUTLASS_DEVICE
204	  ProducerBarrierType* producer_get_barrier(PipelineState state) {
205	    return impl_.producer_get_barrier(state);
206	  }
207	
208	  CUTLASS_DEVICE
209	  void consumer_wait(PipelineState state, ConsumerToken barrier_token = {BarrierStatus::WaitAgain}) {
210	    impl_.consumer_wait(state, barrier_token);
211	  }
212	
